import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
import { Vector2D } from '../types';

interface RotationWheelControlProps {
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (newValue: number) => void;
  isDisabled: boolean;
  className?: string;
}

const WHEEL_SIZE = 120; // Diameter of the wheel
const CENTER = WHEEL_SIZE / 2;
const RADIUS = CENTER - 5; // Radius for the draggable area

export const RotationWheelControl: React.FC<RotationWheelControlProps> = ({
  value,
  min,
  max,
  step,
  onChange,
  isDisabled,
  className = '',
}) => {
  const wheelRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const dragStartAngle = useRef<number>(0);
  const dragStartValue = useRef<number>(0);
  const wheelCenter = useRef<Vector2D>({ x: 0, y: 0 });

  const clampValue = useCallback((val: number) => {
    return Math.max(min, Math.min(max, val));
  }, [min, max]);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (isDisabled) return;
    e.preventDefault();
    setIsDragging(true);

    const rect = wheelRef.current?.getBoundingClientRect();
    if (rect) {
      wheelCenter.current = { x: rect.left + CENTER, y: rect.top + CENTER };
      dragStartValue.current = value;

      const dx = e.clientX - wheelCenter.current.x;
      const dy = e.clientY - wheelCenter.current.y;
      dragStartAngle.current = Math.atan2(dy, dx) * 180 / Math.PI;
    }
  }, [isDisabled, value]);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || isDisabled) return;

    const dx = e.clientX - wheelCenter.current.x;
    const dy = e.clientY - wheelCenter.current.y;
    const currentAngle = Math.atan2(dy, dx) * 180 / Math.PI;

    let angleDelta = currentAngle - dragStartAngle.current;

    // Handle angle wrap-around
    if (angleDelta > 180) angleDelta -= 360;
    if (angleDelta < -180) angleDelta += 360;

    let newValue = dragStartValue.current + angleDelta;
    newValue = clampValue(newValue);
    onChange(newValue);
  }, [isDragging, isDisabled, onChange, clampValue]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  useEffect(() => {
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [handleMouseMove, handleMouseUp]);

  const handleStepChange = useCallback((increment: boolean) => {
    if (isDisabled) return;
    let newValue = increment ? value + step : value - step;
    newValue = clampValue(newValue);
    onChange(newValue);
  }, [isDisabled, value, step, onChange, clampValue]);

  const currentAngleForIndicator = useMemo(() => {
    // Normalize value to be within 0-360 range for display on wheel
    // This assumes min/max could be outside 0-360, but the indicator
    // just needs to represent where it is within a full circle.
    // Let's map min/max range to a 360 degree sweep for the indicator.
    const range = max - min;
    if (range === 0) return 0; // Prevent division by zero
    const normalizedValue = (value - min) / range; // 0 to 1
    return normalizedValue * 360; // 0 to 360 degrees
  }, [value, min, max]);

  const indicatorCoords = useMemo(() => {
    // Position indicator at 0 degrees (top) when value is at its lower bound,
    // and sweep clockwise. 0 degrees in SVG is positive X, 90 deg is positive Y.
    // We want 0 degrees to be straight up (-Y axis).
    const indicatorAngleRad = (currentAngleForIndicator - 90) * Math.PI / 180;
    const x = CENTER + RADIUS * Math.cos(indicatorAngleRad);
    const y = CENTER + RADIUS * Math.sin(indicatorAngleRad);
    return { x, y };
  }, [currentAngleForIndicator]);

  return (
    <div className={`flex items-center justify-center gap-2 ${className} ${isDisabled ? 'opacity-50 pointer-events-none' : ''}`}>
      <button
        onClick={() => handleStepChange(false)}
        className="w-8 h-8 flex items-center justify-center border border-white/20 text-white/70 hover:bg-white/10 transition-colors text-lg font-bold"
        aria-label="Decrement rotation angle"
        disabled={isDisabled}
      >
        -
      </button>

      <div
        ref={wheelRef}
        className="relative flex items-center justify-center"
        style={{ width: WHEEL_SIZE, height: WHEEL_SIZE }}
        onMouseDown={handleMouseDown}
        role="slider" // The whole wheel acts as a slider
        aria-valuenow={value}
        aria-valuemin={min}
        aria-valuemax={max}
        aria-label="Rotation angle" // General label for the wheel
      >
        <svg width={WHEEL_SIZE} height={WHEEL_SIZE} className="absolute inset-0">
          {/* Wheel background */}
          <circle cx={CENTER} cy={CENTER} r={RADIUS} fill="#2D2D2D" stroke="#3A3A3A" strokeWidth="1" />

          {/* Active drag indicator (optional, but good for visual feedback) */}
          {isDragging && (
            <circle cx={CENTER} cy={CENTER} r={RADIUS - 2} fill="none" stroke="#E5E7EB" strokeWidth="2" strokeDasharray="5 5" />
          )}

          {/* Current value indicator (a dot on the circumference) */}
          <circle
            cx={indicatorCoords.x}
            cy={indicatorCoords.y}
            r="4"
            fill="#E5E7EB" /* focus-ring color */
            stroke="#2D2D2D"
            strokeWidth="1"
            className="pointer-events-none"
          />
        </svg>
        <span className="relative text-focus-ring text-lg font-bold tracking-tight pointer-events-none">
          {value.toFixed(0)}°
        </span>
      </div>

      <button
        onClick={() => handleStepChange(true)}
        className="w-8 h-8 flex items-center justify-center border border-white/20 text-white/70 hover:bg-white/10 transition-colors text-lg font-bold"
        aria-label="Increment rotation angle"
        disabled={isDisabled}
      >
        +
      </button>
    </div>
  );
};

import React from 'react';
import { Bone, type BoneProps } from './Bone'; // Import BoneProps type for explicit casting
import { ANATOMY, RIGGING } from '../constants';
import { getJointPositions, getTotalRotation } from '../utils/kinematics';
import { PartName, PartSelection, PartVisibility, AnchorName, Pose, JointConstraint, RenderMode, PARENT_MAP, partNameToPoseKey } from '../types';
import { COLORS_BY_CATEGORY, COLORS } from './Bone'; // Import COLORS_BY_CATEGORY AND COLORS for pin indicator color

interface MannequinProps {
  pose: Pose;
  showOverlay?: boolean;
  selectedParts: PartSelection;
  visibility: PartVisibility;
  pin: AnchorName;
  className?: string;
  onMouseDownOnPart?: (part: PartName, event: React.MouseEvent<SVGGElement>) => void;
  // onHoverOnPart removed as not currently used
  // onDoubleClickOnPart removed as IK/kinetic modes are debuilt
  // onTripleClickOnPart removed as chain selection is debuilt
  onMouseDownOnRoot?: (event: React.MouseEvent<SVGCircleElement>) => void;
  // isAirMode removed as not currently used/debuilt
  // showHighlights removed as selection is handled by `isSelected` prop directly to Bone
  // onToggleCrane removed as crane state is debuilt
  // isCraneActive removed as crane state is debuilt
  // jointModes removed as only FK is supported
  renderMode?: RenderMode; // New prop: 'default', 'wireframe', 'silhouette'
  // bodyRotation removed as it was primarily for Z-depth simulation (darkening limbs), which is removed
}

export const getPartCategory = (part: PartName): string => { // Exported
  switch (part) {
    case PartName.RWrist:
    case PartName.LWrist: return 'hand';
    case PartName.RElbow: // This represents the forearm segment
    case PartName.LElbow: return 'forearm';
    case PartName.RShoulder: // This represents the bicep segment
    case PartName.LShoulder: return 'bicep';
    case PartName.Collar: return 'collar';
    case PartName.Torso: return 'torso';
    case PartName.Waist: return 'waist';
    case PartName.RThigh:
    case PartName.LThigh: return 'thigh';
    case PartName.RSkin: // This represents the shin/calf segment
    case PartName.LSkin: return 'shin';
    case PartName.RAnkle: // This represents the foot segment
    case PartName.LAnkle: return 'foot';
    case PartName.Head: return 'head';
    default: return 'default';
  }
};

// Fix: Exporting getPartCategoryDisplayName to resolve the compilation error.
export const getPartCategoryDisplayName = (part: PartName): string => {
  const category = getPartCategory(part);
  // Simple mapping for display purposes
  switch(category) {
    case 'bicep': return part.startsWith('r') ? 'RIGHT BICEP' : 'LEFT BICEP';
    case 'forearm': return part.startsWith('r') ? 'RIGHT FOREARM' : 'LEFT FOREARM';
    case 'hand': return part.startsWith('r') ? 'RIGHT HAND' : 'LEFT HAND';
    case 'thigh': return part.startsWith('r') ? 'RIGHT THIGH' : 'LEFT THIGH';
    case 'shin': return part.startsWith('r') ? 'RIGHT SHIN' : 'LEFT SHIN';
    case 'foot': return part.startsWith('r') ? 'RIGHT FOOT' : 'LEFT FOOT';
    case 'head': return 'HEAD';
    case 'collar': return 'COLLAR';
    case 'torso': return 'TORSO';
    case 'waist': return 'WAIST';
    default: return part.toUpperCase();
  }
};

export const Mannequin: React.FC<MannequinProps> = ({
  pose,
  showOverlay = true,
  selectedParts,
  visibility,
  pin,
  className = "text-ink",
  onMouseDownOnPart,
  onMouseDownOnRoot,
  renderMode = 'default', // Default renderMode to 'default'
}) => {
  const joints = getJointPositions(pose, pin); // Pass activePin to getJointPositions
  const offsets = pose.offsets || {};

  const PartWrapper = ({ part, children }: { part: PartName; children?: React.ReactNode }) => {
    const isSelected = selectedParts[part];

    const handleMouseDown = (e: React.MouseEvent<SVGGElement>) => { 
      e.stopPropagation(); 
      onMouseDownOnPart?.(part, e); 
    };

    // onDoubleClick and onTripleClick removed

    return (
      <g 
        className="cursor-pointer" 
        onMouseDown={handleMouseDown}
        role="button" // Indicate it's an interactive element
        aria-label={`Select ${getPartCategoryDisplayName(part)}`}
        aria-pressed={isSelected}
      >
        {React.Children.map(children, child =>
          // Explicitly cloneElement and pass `isSelected` and `renderMode`.
          // `constraint` and `darken20Percent` are removed.
          React.isValidElement(child) && child.type === Bone
            ? React.cloneElement(child as React.ReactElement<BoneProps>, { 
                isSelected: isSelected,
                renderMode: renderMode,
              })
            : child
        )}
      </g>
    );
  };

  const ROOT_COLOR = "#5A5A5A"; // Darker grayscale for the root circle
  const PIN_INDICATOR_SIZE = ANATOMY.ROOT_SIZE * 0.7; // Size of the inner circle of the root graphic
  const PIN_INDICATOR_STROKE_COLOR = COLORS.SELECTION; // Light monochrome for stroke
  const PIN_INDICATOR_STROKE_WIDTH = 1;


  return (
    // The `pose.root.x` and `pose.root.y` used here are already compensated by getJointPositions
    <g className={`mannequin-root ${className}`} transform={`translate(${pose.root.x}, ${pose.root.y}) rotate(${pose.bodyRotation})`}>
      {/* Root circle for drag. Also serves as active pin indicator when pin === 'root' */}
      <g 
        onMouseDown={onMouseDownOnRoot} 
        // onDoubleClick removed
        className={'cursor-pointer'} 
        data-no-export={true}
        role="button" // Indicate it's an interactive element
        aria-label="Drag mannequin root"
      >
        {/* Transparent outer circle for larger clickable area */}
        <circle cx="0" cy="0" r={ANATOMY.ROOT_SIZE} fill="currentColor" opacity="0.1" />
        {/* Inner circle - active pin indicator */}
        <circle 
          cx="0" cy="0" r={PIN_INDICATOR_SIZE} 
          fill={pin === 'root' ? COLORS.ANCHOR_RED : ROOT_COLOR} // Red if active pin, else grayscale
          stroke={PIN_INDICATOR_STROKE_COLOR} 
          strokeWidth={PIN_INDICATOR_STROKE_WIDTH} 
        />
      </g>

      {/* Wireframe connection lines (now handled by Bone if in wireframe mode, otherwise removed here) */}
      {/* If you wanted *additional* explicit connection lines here, add logic for renderMode !== 'wireframe' and renderMode !== 'silhouette' */}

      {/* Active Pin Indicator (if not 'root') */}
      {pin !== 'root' && joints[pin as keyof typeof joints] && ( // Ensure the key exists in joints
        <g transform={`translate(${joints[pin as keyof typeof joints].x - pose.root.x}, ${joints[pin as keyof typeof joints].y - pose.root.y})`} data-no-export={true}>
          <circle cx="0" cy="0" r={ANATOMY.ROOT_SIZE} fill="currentColor" opacity="0.1" /> {/* Transparent outer circle */}
          <circle 
            cx="0" cy="0" r={PIN_INDICATOR_SIZE} 
            fill={COLORS.ANCHOR_RED} // Always red if an active (non-root) pin
            stroke={PIN_INDICATOR_STROKE_COLOR} 
            strokeWidth={PIN_INDICATOR_STROKE_WIDTH} 
          />
        </g>
      )}

      <PartWrapper part={PartName.Waist}>
        <Bone 
          rotation={getTotalRotation(PartName.Waist, pose)} 
          length={ANATOMY.WAIST} 
          width={ANATOMY.WAIST_WIDTH} 
          variant="waist-teardrop-pointy-up" 
          drawsUpwards 
          showOverlay={showOverlay} 
          offset={offsets[PartName.Waist]} 
          visible={visibility[PartName.Waist]} 
          partCategory={getPartCategory(PartName.Waist)}
        >
          <PartWrapper part={PartName.Torso}>
            <Bone 
              rotation={getTotalRotation(PartName.Torso, pose)} 
              length={ANATOMY.TORSO} 
              width={ANATOMY.TORSO_WIDTH} 
              variant="torso-teardrop-pointy-down" 
              drawsUpwards 
              showOverlay={showOverlay} 
              offset={offsets[PartName.Torso]} 
              visible={visibility[PartName.Torso]} 
              partCategory={getPartCategory(PartName.Torso)}
            >
              <PartWrapper part={PartName.Collar}>
                <Bone 
                  rotation={getTotalRotation(PartName.Collar, pose)} 
                  length={ANATOMY.COLLAR} 
                  width={ANATOMY.COLLAR_WIDTH} 
                  variant="collar-horizontal-oval-shape" 
                  drawsUpwards 
                  showOverlay={showOverlay} 
                  partCategory={getPartCategory(PartName.Collar)}
                  offset={offsets[PartName.Collar]} 
                  visible={visibility[PartName.Collar]} 
                >

                  <g transform={`translate(0, 0)`}>
                    <PartWrapper part={PartName.Head}>
                      <Bone 
                        rotation={getTotalRotation(PartName.Head, pose)} 
                        length={ANATOMY.HEAD} 
                        width={ANATOMY.HEAD_WIDTH} 
                        variant="head-tall-oval" 
                        drawsUpwards 
                        showOverlay={showOverlay} 
                        offset={offsets[PartName.Head]} 
                        visible={visibility[PartName.Head]} 
                        partCategory={getPartCategory(PartName.Head)}
