          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">RENDER_MODE</span>
            <div className="flex gap-4 justify-between w-full"><span>MODE:</span> <span className="text-focus-ring">{renderMode.toUpperCase()}</span></div>
          </div>
        </DraggablePanel>

        {/* COMMAND LOG (New Draggable Panel) */}
        <DraggablePanel
          id="command-log-panel"
          title="COMMAND_LOG"
          x={panelRects['command-log-panel'].x}
          y={panelRects['command-log-panel'].y}
          minimized={panelRects['command-log-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for command-log: directly below system-status, no gap
            const systemStatusRect = panelRects['system-status-panel'];
            const newY = systemStatusRect.y + systemStatusRect.height; 
            if (panelRects['command-log-panel'].y !== newY) {
              updatePanelPosition('command-log-panel', systemStatusRect.x, newY, panelRects['command-log-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['command-log-panel']}
          className="w-56"
        >
           <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest">
            <span className="text-white/30 mb-1 border-b border-white/10 pb-1">COMMAND_UNIT</span>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[V]</span> <span>Optics</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[P]</span> <span>Pin</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[R]</span> <span>Render Mode</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Z]</span> <span>Undo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Y]</span> <span>Redo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DRAG</span> <span>Posing</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DBL-CLK</span> <span>Kinetic Mode</span></div>
            <div className="mt-2 text-white/30 border-b border-white/10 pb-1">KINETIC_LEGEND</div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.PURPLE_STRETCH}}></span> <span className="text-accent-purple">STRETCH</span></div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.GREEN_CURL}}></span> <span className="text-accent-green">CURL</span></div>
          </div>
        </DraggablePanel>

        {/* POSE DATA TERMINAL (New Draggable Panel) */}
        <DraggablePanel
          id="pose-data-terminal-panel"
          title="POSE_DATA_TERMINAL"
          x={panelRects['pose-data-terminal-panel'].x}
          y={panelRects['pose-data-terminal-panel'].y}
          minimized={panelRects['pose-data-terminal-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for pose-data-terminal: directly below command-log, no gap
            const commandLogRect = panelRects['command-log-panel'];
            const newY = commandLogRect.y + commandLogRect.height; 
            if (panelRects['pose-data-terminal-panel'].y !== newY) {
              updatePanelPosition('pose-data-terminal-panel', commandLogRect.x, newY, panelRects['pose-data-terminal-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pose-data-terminal-panel']}
          className="w-56"
        >
          <div className="text-white/70 text-[8px] whitespace-pre-wrap break-all h-full overflow-y-auto custom-scrollbar">
            {poseToString(activePose)}
          </div>
        </DraggablePanel>

        {/* This div wraps the entire mannequin rendering area, no specific z-index here */}
        <div className="w-full h-full bg-selection-super-light bg-triangle-grid flex items-center justify-center relative">
          <Scanlines />
          {showSplash && (
            <div className="absolute top-[8%] left-0 right-0 z-30 flex items-center justify-center pointer-events-none">
              <h1 className="text-6xl font-archaic text-paper/80 animate-terminal-boot tracking-widest uppercase">BITRUVIUS</h1>
            </div>
          )}

          <svg 
            ref={svgRef} 
            width="100%" 
            height="100%" 
            viewBox={autoViewBox} 
            className="overflow-visible relative z-10" 
          >
            <SystemGuides floorY={FLOOR_HEIGHT} /> 
            <g>
              <Mannequin
                pose={activePose}
                showOverlay={true}
                selectedParts={selectedParts}
                visibility={visibility}
                pin={activePin}
                className="text-black"
                onMouseDownOnPart={handleMouseDownOnPart}
                onDoubleClickOnPart={handleDoubleClickOnPart} // Reintroduced
                onMouseDownOnRoot={(e) => { 
                  e.stopPropagation(); 
                  setIsCraneDragging(true); 
                  dragStartInfo.current = { startX: 0, y: 0, startRootX: activePose.root.x, startRootY: activePose.root.y }; 
                }}
                jointModes={jointModes} // Reintroduced
                renderMode={renderMode}
              />
            </g>
          </svg>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import { Pose, PartName, PartSelection, PartVisibility, AnchorName, partNameToPoseKey, PARENT_MAP, CHILD_MAP, LIMB_SEQUENCES, JointConstraint, RenderMode, Vector2D } from './types';
import { RESET_POSE, FLOOR_HEIGHT, SCALE_FACTOR, JOINT_LIMITS, FLOOR_SINK_BUFFER, GROUND_SINK_REMAINING_PROPORTION } from './constants'; 
import { getJointPositions, solveArmIK, solveLegIK, getShortestAngleDiffDeg } from './utils/kinematics';
import { Scanlines, SystemGuides } from './components/SystemGrid';
import { Mannequin, getPartCategory, getPartCategoryDisplayName } from './components/Mannequin'; 
import { DraggablePanel } from './components/DraggablePanel';
import { COLORS_BY_CATEGORY, COLORS } from './components/Bone'; // Import COLORS_BY_CATEGORY and COLORS for kinetic mode display
import { poseToString } from './utils/pose-parser'; // Import poseToString
import { RotationWheelControl } from './components/RotationWheelControl'; // Import RotationWheelControl

type ViewMode = 'zoomed' | 'default' | 'lotte' | 'wide';

interface PanelRect {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  minimized: boolean;
}

const App: React.FC = () => {
  const [activePose, setActivePose] = useState<Pose>(RESET_POSE);
  const undoStack = useRef<Pose[]>([]);
  const redoStack = useRef<Pose[]>([]);


  const [viewMode, setViewMode] = useState<ViewMode>('default');
  const [activePin, setActivePin] = useState<AnchorName>(PartName.Waist); // Default to Waist
  const [renderMode, setRenderMode] = useState<RenderMode>('default');

  const [selectedParts, setSelectedParts] = useState<PartSelection>(() => {
    const initialSelection: PartSelection = Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: false }), {} as PartSelection);
    initialSelection[PartName.Waist] = true; 
    return initialSelection;
  });

  const [visibility] = useState<PartVisibility>(() => Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: true }), {} as PartVisibility));

  // Joint modes state - Reintroduced for kinetic behaviors
  const [jointModes, setJointModes] = useState<Record<PartName, JointConstraint>>(() => 
    Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: 'fk' }), {} as Record<PartName, JointConstraint>)
  );

  // Joint strengths removed (no kinetic behaviors)
  // Broadcast mode removed (no kinetic behaviors)

  const [isAdjusting, setIsAdjusting] = useState(false); // For standard rotation
  const [rotatingPart, setRotatingPart] = useState<PartName | null>(null);
  const rotationStartInfo = useRef<{ 
    startAngle: number; 
    startRotationValue: number; 
    pointerX: number; 
    pointerY: number;
    initialPinnedPos: Vector2D | null;
  } | null>(null);

  // IK drag states removed (no IK)
  const [isEffectorDragging, setIsEffectorDragging] = useState(false); // Kept for isValidMove check, always false
  const [effectorPart, setEffectorPart] = useState<PartName | null>(null); // Kept for isValidMove check, always null

  const svgRef = useRef<SVGSVGElement>(null); 
  // Crane states removed (no crane)
  const [isCraneActive] = useState(false); // Always false
  const [isCraneDragging, setIsCraneDragging] = useState(false); // For dragging root
  const dragStartInfo = useRef<{ startX: number; startY: number; startRootX: number; startRootY: number } | null>(dragStartInfoInitial());

  // Function to provide initial dragStartInfo value, preventing it from being null
  function dragStartInfoInitial() {
    return { startX: 0, y: 0, startRootX: 0, startRootY: 0 };
  }

  const [showSplash, setShowSplash] = useState(true);
  const [isAirMode] = useState(false); // Always false

  // Panel Z-index management
  const [panelZIndices, setPanelZIndices] = useState<Record<string, number>>({
    'pin-control-panel': 102, // Higher Z-index
    'scalar-hub-panel': 101, // Higher Z-index
    'system-status-panel': 100, // Higher Z-index
    'command-log-panel': 99, 
    'pose-data-terminal-panel': 98, // New panel
  });
  const nextZIndex = useRef<number>(103); // Start higher than initial values

  const bringPanelToFront = useCallback((id: string) => {
    setPanelZIndices(prev => {
      const newZIndices = { ...prev };
      newZIndices[id] = nextZIndex.current++;
      return newZIndices;
    });
  }, []);

  // --- Panel Position/Size Management ---
  const [panelRects, setPanelRects] = useState<Record<string, PanelRect>>({
    'pin-control-panel': { id: 'pin-control-panel', x: 16, y: 16, width: 224, height: 230, minimized: false }, // Adjusted height to accommodate pin rotation wheel
    'scalar-hub-panel': { id: 'scalar-hub-panel', x: 16, y: 16 + 230, width: 224, height: 250, minimized: false }, 
    'system-status-panel': { id: 'system-status-panel', x: window.innerWidth - 224 - 16, y: 16, width: 224, height: 180, minimized: false }, 
    'command-log-panel': { id: 'command-log-panel', x: window.innerWidth - 224 - 16, y: 16 + 180, width: 224, height: 180, minimized: false }, 
    'pose-data-terminal-panel': { id: 'pose-data-terminal-panel', x: window.innerWidth - 224 - 16, y: 16 + 180 + 180, width: 224, height: 150, minimized: false }, 
  });

  const updatePanelRect = useCallback((id: string, newRect: Omit<PanelRect, 'x' | 'y'>) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.width !== newRect.width || existingRect.height !== newRect.height || existingRect.minimized !== newRect.minimized) {
        return { ...prev, [id]: { ...existingRect, ...newRect } };
      }
      return prev;
    });
  }, []);

  const updatePanelPosition = useCallback((id: string, newX: number, newY: number, minimized: boolean) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.x !== newX || existingRect.y !== newY || existingRect.minimized !== minimized) {
        return { ...prev, [id]: { ...existingRect, x: newX, y: newY, minimized: minimized } };
      }
      return prev;
    });
  }, []);
  // --- End Panel Position/Size Management ---

  const primarySelectedPart = useMemo(() => {
    return (Object.entries(selectedParts).find(([p, sel]) => sel)?.[0]) as PartName | undefined;
  }, [selectedParts]);

  const autoViewBox = useMemo(() => {
    const configs = {
      zoomed: { x: -900, y: 1950, w: 1800, h: 1550 },
      default: { x: -1112.5, y: 1287.5, w: 2225, h: 2212.5 },
      lotte: { x: -1325, y: 625, w: 2650, h: 2875 },
      wide: { x: -1750, y: -700, w: 3500, h: 4200 }
    };
    const c = configs[viewMode];
    return `${c.x} ${c.y} ${c.w} ${c.h}`;
  }, [viewMode]);

  // --- Physics Validation Logic ---
  const isValidMove = useCallback((
    potentialPose: Pose,
    originalPose: Pose,
    activePin: AnchorName,
    initialPinnedPos: Vector2D | null,
    isCraneDragging: boolean,
    isEffectorDragging: boolean, // Will always be false now
    partBeingRotated: PartName | null,
    isAirMode: boolean, // Will always be false now
  ): boolean => {
    if (isAirMode) return true; // No grounding/pinning checks in air mode

    const potentialJoints = getJointPositions(potentialPose, activePin); // Pass activePin
    const originalJoints = getJointPositions(originalPose, activePin); // Pass activePin

    // 1. Check Pin Immovability
    if (!isCraneDragging && initialPinnedPos && activePin) {
        const currentPinnedPosInPotentialPose = potentialJoints[activePin as keyof typeof potentialJoints];
        if (currentPinnedPosInPotentialPose) {
            const dx = currentPinnedPosInPotentialPose.x - initialPinnedPos.x;
            const dy = currentPinnedPosInPotentialPose.y - initialPinnedPos.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            const PIN_TOLERANCE = 2; // Pixels
            if (distance > PIN_TOLERANCE) {
                return false; // Pin moved too much
            }
        }
    }

    // 2. Check Ground Collision
    const isFootRelatedPart = (part: PartName | null) =>
      part === PartName.LAnkle || part === PartName.RAnkle || part === PartName.LSkin || part === PartName.RSkin; 

    const relevantToGrounding = isCraneDragging || isEffectorDragging || isFootRelatedPart(partBeingRotated);

    if (relevantToGrounding) {
      const lFootTipY = potentialJoints.lFootTip?.y || -Infinity;
      const rFootTipY = potentialJoints.rFootTip?.y || -Infinity;
      const lowestFootTipY = Math.max(lFootTipY, rFootTipY);

      const GROUND_COLLISION_THRESHOLD = 2; // Pixels below floor allowed as buffer
      if (lowestFootTipY > FLOOR_HEIGHT + GROUND_COLLISION_THRESHOLD) {
          return false; // Collision detected
      }
    }

    return true;
  }, [activePin, isAirMode, isCraneDragging]); 

  // Replaced handlePoseChange with this gatekeeper function
  const validateAndApplyPoseUpdate = useCallback((
      proposedUpdates: Partial<Pose>,
      partBeingDirectlyManipulated: PartName | null, // The part changed by FK or IK target
      isEffectorDrag: boolean, // Is this an IK drag operation? - Will always be false
  ) => {
      setActivePose(prev => {
          let tentativeNextPose: Pose = { ...prev, ...proposedUpdates };

          // Validate the new pose *after* kinetic ripple (which is now just direct update)
          if (!isValidMove(
              tentativeNextPose,
              prev, // The pose before this attempt
              activePin,
              rotationStartInfo.current?.initialPinnedPos || null,
              isCraneDragging, 
              isEffectorDrag,
              partBeingDirectlyManipulated,
              isAirMode,
          )) {
              return prev; // Revert to previous pose if invalid
          }

          // If valid, push to undo stack and return new pose
          undoStack.current.push(prev);
          redoStack.current.length = 0; // Clear redo stack on new action
          return tentativeNextPose;
      });
  }, [activePin, isAirMode, isCraneDragging, isValidMove]); // Removed jointModes, jointStrengths from deps

  const handleUndo = useCallback(() => {
    if (undoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = undoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleRedo = useCallback(() => {
    if (redoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = redoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!svgRef.current) return;
    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    if (isCraneDragging && dragStartInfo.current) {
      const dx = transformedPoint.x - dragStartInfo.current.startX;
      const dy = transformedPoint.y - dragStartInfo.current.startY;

      const newRootX = dragStartInfo.current.startRootX + dx;
      const newRootY = dragStartInfo.current.startRootY + dy;

      validateAndApplyPoseUpdate({ root: { x: newRootX, y: newRootY } }, null, false);

    } else if (isAdjusting && rotatingPart && rotationStartInfo.current) { // Standard rotation drag
      const joints = getJointPositions(activePose, activePin); // Pass activePin
      const pivot = joints[rotatingPart]; 
      if (!pivot) return;

      const currentAngleDeg = Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI;
      const startAngleDeg = rotationStartInfo.current.startAngle; 

      const angleDeltaDeg = getShortestAngleDiffDeg(currentAngleDeg, startAngleDeg);

      let newRotationValue = rotationStartInfo.current.startRotationValue + angleDeltaDeg;
      const partKey = partNameToPoseKey[rotatingPart];
      const limits = JOINT_LIMITS[partKey];

      if (limits) {
        newRotationValue = Math.max(limits.min, Math.min(limits.max, newRotationValue));
      }

      validateAndApplyPoseUpdate({ [partKey]: newRotationValue }, rotatingPart, false);

    } 
    // Removed IK drag for hands/feet
  }, [isAdjusting, rotatingPart, isCraneDragging, activePose, validateAndApplyPoseUpdate, activePin]); // Added activePin to deps

  const handleMouseUp = useCallback(() => {
    setIsAdjusting(false);
    setRotatingPart(null);
    setIsCraneDragging(false);
    setEffectorPart(null); 
    setIsEffectorDragging(false); 
    rotationStartInfo.current = null;
    dragStartInfo.current = dragStartInfoInitial(); 
  }, []);

  const getInitialPinnedPos = useCallback(() => {
    const joints = getJointPositions(activePose, activePin); // Pass activePin
    let initialPinnedPos: Vector2D | null = null;

    if (activePin === 'root') {
      initialPinnedPos = joints.root;
    } else if (activePin === 'lFootTip') {
      initialPinnedPos = joints.lFootTip;
    } else if (activePin === 'rFootTip') {
      initialPinnedPos = joints.rFootTip;
    } else { // It's a PartName
      initialPinnedPos = joints[activePin];
    }

    // Clamp initialPinnedPos.y to FLOOR_HEIGHT if it's a foot tip, to prevent pinning below ground
    if (initialPinnedPos && (activePin === 'lFootTip' || activePin === 'rFootTip')) {
      initialPinnedPos = { ...initialPinnedPos, y: Math.min(initialPinnedPos.y, FLOOR_HEIGHT) };
    }
    return initialPinnedPos;
  }, [activePose, activePin]);

  const handleDoubleClickOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    // Cycle joint constraint mode: fk -> stretch -> curl -> stretch -> curl ...
    setJointModes(prev => {
      const currentMode = prev[part];
      let nextMode: JointConstraint;
      if (currentMode === 'fk') {
        nextMode = 'stretch';
      } else if (currentMode === 'stretch') {
        nextMode = 'curl';
      } else if (currentMode === 'curl') {
        nextMode = 'stretch';
      } else {
        nextMode = 'fk'; // Fallback to fk, though should not happen with current enum
      }
      return { ...prev, [part]: nextMode };
    });
  }, []);

  const handleMouseDownOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    if (!svgRef.current) return;

    setSelectedParts(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(k => next[k as PartName] = k === part);
      return next;
    });

    const joints = getJointPositions(activePose, activePin); // Pass activePin
    const pivot = joints[part]; 
    if (!pivot) return;

    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    setIsAdjusting(true);
    setRotatingPart(part);
    rotationStartInfo.current = {
      startAngle: Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI,
      startRotationValue: (activePose as any)[partNameToPoseKey[part]] || 0,
      pointerX: transformedPoint.x, pointerY: transformedPoint.y, initialPinnedPos: getInitialPinnedPos()
    };
  }, [activePose, activePin, getInitialPinnedPos]);

  // Removed applyJointMode (no kinetic behaviors)
  // Removed applyJointStrength (no kinetic behaviors)

  // Function to cycle render modes
  const cycleRenderMode = useCallback(() => {
    setRenderMode(prev => {
      if (prev === 'default') return 'wireframe';
      if (prev === 'wireframe') return 'silhouette'; // 'grayscale' render mode removed, 'silhouette' is now solid black fill
      return 'default';
    });
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'v') setViewMode(prev => prev === 'zoomed' ? 'default' : prev === 'default' ? 'lotte' : prev === 'lotte' ? 'wide' : 'zoomed');
      if (e.key === 'p') setActivePin(prev => {
        if (prev === PartName.Waist) return PartName.LAnkle;
        if (prev === PartName.LAnkle) return 'lFootTip'; 
        if (prev === 'lFootTip') return PartName.RAnkle; // Cycle to right ankle
        if (prev === PartName.RAnkle) return 'rFootTip'; // Cycle to right tiptoe
        if (prev === 'rFootTip') return 'root'; // Cycle to root
        return PartName.Waist; // Cycle back to Waist
      });
      // 'b' for broadcast mode removed
      if (e.key === 'r') cycleRenderMode(); // Shortcut for render mode
      if (e.key === 'z' && (e.ctrlKey || e.metaKey)) { // Ctrl+Z or Cmd+Z for undo
        e.preventDefault();
        handleUndo();
      }
      if (e.key === 'y' && (e.ctrlKey || e.metaKey)) { // Ctrl+Y or Cmd+Y for redo
        e.preventDefault();
        handleRedo();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    const timer = setTimeout(() => setShowSplash(false), 2000);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      clearTimeout(timer);
    };
  }, [handleMouseMove, handleMouseUp, handleUndo, handleRedo, cycleRenderMode]);

  // Removed useEffect for global grayscale filter

  const getPinName = (pin: AnchorName) => {
    if (pin === PartName.Waist) return 'WAIST';
    if (pin === PartName.LAnkle) return 'LEFT ANKLE';
    if (pin === 'lFootTip') return 'LEFT TIPTOE';
    if (pin === PartName.RAnkle) return 'RIGHT ANKLE';
    if (pin === 'rFootTip') return 'RIGHT TIPTOE';
    if (pin === 'root') return 'ROOT';
    return 'UNKNOWN';
  };

  const getKineticModeDisplayName = (mode: JointConstraint) => {
    switch (mode) {
      case 'fk': return 'FK (Default)';
      case 'stretch': return 'KINETIC_STRETCH';
      case 'curl': return 'KINETIC_CURL';
      default: return 'UNKNOWN';
    }
  };

  const getKineticModeDisplayColorClass = (mode: JointConstraint) => {
    switch (mode) {
      case 'stretch': return 'text-accent-purple';
      case 'curl': return 'text-accent-green';
      case 'fk': return 'text-focus-ring';
      default: return 'text-white/70';
    }
  };


  const handlePartRotationWheelChange = useCallback((newValue: number) => {
    if (!primarySelectedPart) return;
    const partKey = partNameToPoseKey[primarySelectedPart];

    validateAndApplyPoseUpdate({ [partKey]: newValue }, primarySelectedPart, false);
  }, [primarySelectedPart, validateAndApplyPoseUpdate]);

  const handleBodyRotationWheelChange = useCallback((newValue: number) => {
    validateAndApplyPoseUpdate({ bodyRotation: newValue }, null, false); // No specific part, not IK
  }, [validateAndApplyPoseUpdate]);

  const allPanelRectsArray = useMemo(() => Object.values(panelRects), [panelRects]);

  return (
    <div className="w-full h-full bg-mono-darker shadow-2xl flex flex-col relative touch-none fixed inset-0 z-50 overflow-hidden text-ink font-mono">
      <div className="relative flex h-full w-full">
        {/* PIN CONTROL (Draggable Panel) */}
        <DraggablePanel
          id="pin-control-panel"
          title="PIN_CONTROL"
          x={panelRects['pin-control-panel'].x}
          y={panelRects['pin-control-panel'].y}
          minimized={panelRects['pin-control-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pin-control-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-left">
            <span className="text-white/40 text-[8px] uppercase">Pin_Location</span>
            <div className="grid grid-cols-2 gap-1">
              {([PartName.Waist, PartName.LAnkle, 'lFootTip', PartName.RAnkle, 'rFootTip', 'root'] as AnchorName[]).map(pinOption => (
                <button
                  key={pinOption}
                  onClick={() => setActivePin(pinOption)}
                  className={`text-[9px] text-left px-2 py-1 transition-all border ${
                    activePin === pinOption
                    ? 'bg-accent-red/30 border-accent-red text-accent-red' // Red for active pin
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={activePin === pinOption}
                  aria-label={`Set pin location to ${getPinName(pinOption)}`}
                >
                  {getPinName(pinOption)}
                </button>
              ))}
            </div>
          </div>

          <div className="flex flex-col gap-1 border-t border-white/10 pt-2 mt-4 items-center">
            <span className="text-white/40 uppercase text-[8px]">Body_Rotation_Angle</span>
            <RotationWheelControl
              value={activePose.bodyRotation || 0}
              min={-180} // Full 360 degree rotation range
              max={180}
              step={5}
              onChange={handleBodyRotationWheelChange}
              isDisabled={false} // Body rotation always adjustable
              className="my-2"
            />
          </div>
        </DraggablePanel>

        {/* SCALAR HUB (LEFT PANEL) - Positioned dynamically below PIN_CONTROL */}
        <DraggablePanel
          id="scalar-hub-panel"
          title="SCALAR_HUB"
          x={panelRects['scalar-hub-panel'].x}
          y={panelRects['scalar-hub-panel'].y}
          minimized={panelRects['scalar-hub-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for scalar-hub: directly below pin-control, no gap
            const pinControlRect = panelRects['pin-control-panel'];
            const newY = pinControlRect.y + pinControlRect.height; // No 16px gap
            if (panelRects['scalar-hub-panel'].y !== newY) {
              updatePanelPosition('scalar-hub-panel', pinControlRect.x, newY, panelRects['scalar-hub-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['scalar-hub-panel']}
          className="w-56"
          extraTitleContent={primarySelectedPart && <span className="text-accent-red animate-pulse text-[8px]">ACTIVE_PIVOT</span>}
        >
          {/* SCALAR_INFO_PANE */}
          <div className="bg-white/5 p-2 rounded border border-white/10 mb-3 flex flex-col gap-2">
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full" style={{ backgroundColor: primarySelectedPart ? COLORS_BY_CATEGORY[getPartCategory(primarySelectedPart)] : '#9CA3AF' }}></span>
              <span className="text-white/70 text-[9px] uppercase font-bold">
                {primarySelectedPart ? getPartCategoryDisplayName(primarySelectedPart) : 'WHOLE FIGURE'}
              </span>
            </div>
            <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
              <span className="text-white/40 uppercase text-[8px]">Rotation_Angle</span>
              <RotationWheelControl
                value={primarySelectedPart ? activePose[partNameToPoseKey[primarySelectedPart]] || 0 : 0}
                min={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.min || -180 : -180}
                max={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.max || 180 : 180}
                step={5}
                onChange={handlePartRotationWheelChange}
                isDisabled={!primarySelectedPart}
                className="my-2"
              />
            </div>
            {primarySelectedPart && (
              <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
                <span className="text-white/40 uppercase text-[8px]">Kinetic_Mode</span>
                <button
                  onClick={(e) => primarySelectedPart && handleDoubleClickOnPart(primarySelectedPart, e as React.MouseEvent<SVGGElement>)}
                  disabled={!primarySelectedPart}
                  className={`w-full text-[9px] font-bold text-center px-2 py-1 transition-all border ${
                    !primarySelectedPart
                      ? 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                      : `bg-white/10 border-white/20 hover:bg-white/20 ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`
                  }`}
                  aria-label={`Toggle Kinetic Mode for ${getPartCategoryDisplayName(primarySelectedPart)}. Current mode: ${getKineticModeDisplayName(jointModes[primarySelectedPart])}`}
                  aria-pressed={jointModes[primarySelectedPart] !== 'fk'}
                >
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </button>
              </div>
            )}
          </div>

          {/* Undo/Redo Buttons */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex justify-between gap-2">
            <button
              onClick={handleUndo}
              disabled={undoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                undoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Undo last action"
            >
              UNDO
            </button>
            <button
              onClick={handleRedo}
              disabled={redoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                redoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Redo last action"
            >
              REDO
            </button>
          </div>

          {/* Optics Mode Selector */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex flex-col gap-1">
            <span className="text-white/40 text-[8px] uppercase">Optics_Mode</span>
            <div className="flex flex-col gap-1">
              {(['default', 'wireframe', 'silhouette'] as RenderMode[]).map(mode => (
                <button
                  key={mode}
                  onClick={() => setRenderMode(mode)}
                  className={`text-[9px] text-center px-2 py-1 transition-all border ${
                    renderMode === mode 
                    ? 'bg-selection/30 border-selection text-selection' 
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={renderMode === mode}
                  aria-label={`Set render mode to ${mode === 'silhouette' ? 'Monochrome Fill' : mode.toUpperCase()}`}
                >
                  {mode === 'silhouette' ? 'MONOCHROME_FILL' : mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        </DraggablePanel>

        {/* SYSTEM STATUS (RIGHT PANEL - Pin Box and Active Limb Box) */}
        <DraggablePanel
          id="system-status-panel"
          title="MONITOR_O1"
          x={panelRects['system-status-panel'].x}
          y={panelRects['system-status-panel'].y}
          minimized={panelRects['system-status-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['system-status-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">OPTICS_VIEW</span>
            <div className="flex gap-4 justify-between w-full"><span>MODE:</span> <span className="text-accent-green">{viewMode}</span></div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIN_CONFIGURATION</span>
            <div className="flex gap-4 justify-between w-full"><span>STATE:</span> <span className="text-accent-red">{getPinName(activePin)}</span></div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIVOT_STATUS</span>
            <div className="flex gap-4 justify-between w-full"><span>ACTIVE:</span> <span className="text-focus-ring">{primarySelectedPart || 'NONE'}</span></div>
          </div>

          {primarySelectedPart && (
            <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
              <span className="text-white/40 text-[8px] mb-1">KINETIC_MODE</span>
              <div className="flex gap-4 justify-between w-full">
                <span>STATE:</span> 
                <span className={`text-[9px] font-bold ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`}>
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </span>
              </div>
            </div>
          )}

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">RENDER_MODE</span>
            <div className="flex gap-4 justify-between w-full"><span>MODE:</span> <span className="text-focus-ring">{renderMode.toUpperCase()}</span></div>
          </div>
        </DraggablePanel>

        {/* COMMAND LOG (New Draggable Panel) */}
        <DraggablePanel
          id="command-log-panel"
          title="COMMAND_LOG"
          x={panelRects['command-log-panel'].x}
          y={panelRects['command-log-panel'].y}
          minimized={panelRects['command-log-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for command-log: directly below system-status, no gap
            const systemStatusRect = panelRects['system-status-panel'];
            const newY = systemStatusRect.y + systemStatusRect.height; 
            if (panelRects['command-log-panel'].y !== newY) {
              updatePanelPosition('command-log-panel', systemStatusRect.x, newY, panelRects['command-log-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['command-log-panel']}
          className="w-56"
        >
           <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest">
            <span className="text-white/30 mb-1 border-b border-white/10 pb-1">COMMAND_UNIT</span>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[V]</span> <span>Optics</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[P]</span> <span>Pin</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[R]</span> <span>Render Mode</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Z]</span> <span>Undo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Y]</span> <span>Redo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DRAG</span> <span>Posing</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DBL-CLK</span> <span>Kinetic Mode</span></div>
            <div className="mt-2 text-white/30 border-b border-white/10 pb-1">KINETIC_LEGEND</div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.PURPLE_STRETCH}}></span> <span className="text-accent-purple">STRETCH</span></div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.GREEN_CURL}}></span> <span className="text-accent-green">CURL</span></div>
          </div>
        </DraggablePanel>

        {/* POSE DATA TERMINAL (New Draggable Panel) */}
        <DraggablePanel
          id="pose-data-terminal-panel"
          title="POSE_DATA_TERMINAL"
          x={panelRects['pose-data-terminal-panel'].x}
          y={panelRects['pose-data-terminal-panel'].y}
          minimized={panelRects['pose-data-terminal-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for pose-data-terminal: directly below command-log, no gap
            const commandLogRect = panelRects['command-log-panel'];
            const newY = commandLogRect.y + commandLogRect.height; 
            if (panelRects['pose-data-terminal-panel'].y !== newY) {
              updatePanelPosition('pose-data-terminal-panel', commandLogRect.x, newY, panelRects['pose-data-terminal-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pose-data-terminal-panel']}
          className="w-56"
        >
          <div className="text-white/70 text-[8px] whitespace-pre-wrap break-all h-full overflow-y-auto custom-scrollbar">
            {poseToString(activePose)}
          </div>
        </DraggablePanel>

        {/* This div wraps the entire mannequin rendering area, no specific z-index here */}
        <div className="w-full h-full bg-selection-super-light bg-triangle-grid flex items-center justify-center relative">
          <Scanlines />
          {showSplash && (
            <div className="absolute top-[8%] left-0 right-0 z-30 flex items-center justify-center pointer-events-none">
              <h1 className="text-6xl font-archaic text-paper/80 animate-terminal-boot tracking-widest uppercase">BITRUVIUS</h1>
            </div>
          )}

          <svg 
            ref={svgRef} 
            width="100%" 
            height="100%" 
            viewBox={autoViewBox} 
            className="overflow-visible relative z-10" 
          >
            <SystemGuides floorY={FLOOR_HEIGHT} /> 
            <g>
              <Mannequin
                pose={activePose}
                showOverlay={true}
                selectedParts={selectedParts}
                visibility={visibility}
                pin={activePin}
                className="text-black"
                onMouseDownOnPart={handleMouseDownOnPart}
                onDoubleClickOnPart={handleDoubleClickOnPart} // Reintroduced
                onMouseDownOnRoot={(e) => { 
                  e.stopPropagation(); 
                  setIsCraneDragging(true); 
                  dragStartInfo.current = { startX: 0, y: 0, startRootX: activePose.root.x, startRootY: activePose.root.y }; 
                }}
                jointModes={jointModes} // Reintroduced
                renderMode={renderMode}
              />
            </g>
          </svg>
        </div>
      </div>
    </div>
  );
};

