    'scalar-hub-panel': { id: 'scalar-hub-panel', x: 16, y: 16 + 230, width: 224, height: 250, minimized: false }, 
    'system-status-panel': { id: 'system-status-panel', x: window.innerWidth - 224 - 16, y: 16, width: 224, height: 180, minimized: false }, 
    'command-log-panel': { id: 'command-log-panel', x: window.innerWidth - 224 - 16, y: 16 + 180, width: 224, height: 180, minimized: false }, 
    'pose-data-terminal-panel': { id: 'pose-data-terminal-panel', x: window.innerWidth - 224 - 16, y: 16 + 180 + 180, width: 224, height: 150, minimized: false }, 
  });

  const updatePanelRect = useCallback((id: string, newRect: Omit<PanelRect, 'x' | 'y'>) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.width !== newRect.width || existingRect.height !== newRect.height || existingRect.minimized !== newRect.minimized) {
        return { ...prev, [id]: { ...existingRect, ...newRect } };
      }
      return prev;
    });
  }, []);

  const updatePanelPosition = useCallback((id: string, newX: number, newY: number, minimized: boolean) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.x !== newX || existingRect.y !== newY || existingRect.minimized !== minimized) {
        return { ...prev, [id]: { ...existingRect, x: newX, y: newY, minimized: minimized } };
      }
      return prev;
    });
  }, []);
  // --- End Panel Position/Size Management ---

  const primarySelectedPart = useMemo(() => {
    return (Object.entries(selectedParts).find(([p, sel]) => sel)?.[0]) as PartName | undefined;
  }, [selectedParts]);

  // Dynamically calculate viewBox based on viewMode and windowSize
  const autoViewBox = useMemo(() => {
    const configs = {
      zoomed: { x: -900, y: 1950, w: 1800, h: 1550 },
      default: { x: -1112.5, y: 1287.5, w: 2225, h: 2212.5 },
      lotte: { x: -1325, y: 625, w: 2650, h: 2875 },
      wide: { x: -1750, y: -700, w: 3500, h: 4200 },
    };

    if (viewMode === 'mobile') {
      const screenAspectRatio = windowSize.innerWidth / windowSize.innerHeight;

      // Calculate the approximate full height of the mannequin in SVG units
      const mannequinIntrinsicHeight = (
        ANATOMY.HEAD +
        ANATOMY.HEAD_NECK_GAP_OFFSET +
        ANATOMY.COLLAR +
        ANATOMY.TORSO +
        ANATOMY.WAIST +
        ANATOMY.LEG_UPPER +
        ANATOMY.LEG_LOWER +
        ANATOMY.FOOT
      );

      // Define desired vertical content height including some padding
      const verticalPaddingRatio = 0.20; // 20% padding above and below mannequin
      const contentHeightInSVGUnits = mannequinIntrinsicHeight * (1 + verticalPaddingRatio);

      const viewBoxHeight = contentHeightInSVGUnits;
      const viewBoxWidth = viewBoxHeight * screenAspectRatio;

      // Position the floor (FLOOR_HEIGHT) slightly above the very bottom of the viewBox
      const groundPlaneBuffer = GROUND_STRIP_HEIGHT * 1.5; // Ensure ground strip is visible + some buffer
      const desiredViewBoxBottom = FLOOR_HEIGHT + groundPlaneBuffer;
      const viewBoxY = desiredViewBoxBottom - viewBoxHeight;
      const viewBoxX = -viewBoxWidth / 2; // Center horizontally

      return `${viewBoxX} ${viewBoxY} ${viewBoxWidth} ${viewBoxHeight}`;

    } else {
      const c = configs[viewMode];
      return `${c.x} ${c.y} ${c.w} ${c.h}`;
    }
  }, [viewMode, windowSize.innerWidth, windowSize.innerHeight]);

  // --- Physics Validation Logic ---
  const isValidMove = useCallback((
    potentialPose: Pose,
    originalPose: Pose,
    activePin: AnchorName,
    initialPinnedPos: Vector2D | null,
    isCraneDragging: boolean,
    isEffectorDragging: boolean, // Will always be false now
    partBeingRotated: PartName | null,
    isAirMode: boolean, // Will always be false now
  ): boolean => {
    if (isAirMode) return true; // No grounding/pinning checks in air mode

    const potentialJoints = getJointPositions(potentialPose, activePin); // Pass activePin
    const originalJoints = getJointPositions(originalPose, activePin); // Pass activePin

    // 1. Check Pin Immovability
    if (!isCraneDragging && initialPinnedPos && activePin) {
        const currentPinnedPosInPotentialPose = potentialJoints[activePin as keyof typeof potentialJoints];
        if (currentPinnedPosInPotentialPose) {
            const dx = currentPinnedPosInPotentialPose.x - initialPinnedPos.x;
            const dy = currentPinnedPosInPotentialPose.y - initialPinnedPos.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            const PIN_TOLERANCE = 2; // Pixels
            if (distance > PIN_TOLERANCE) {
                return false; // Pin moved too much
            }
        }
    }

    // 2. Check Ground Collision
    const isFootRelatedPart = (part: PartName | null) =>
      part === PartName.LAnkle || part === PartName.RAnkle || part === PartName.LSkin || part === PartName.RSkin; 

    const relevantToGrounding = isCraneDragging || isEffectorDragging || isFootRelatedPart(partBeingRotated);

    if (relevantToGrounding) {
      const lFootTipY = potentialJoints.lFootTip?.y || -Infinity;
      const rFootTipY = potentialJoints.rFootTip?.y || -Infinity;
      const lowestFootTipY = Math.max(lFootTipY, rFootTipY);

      const GROUND_COLLISION_THRESHOLD = 2; // Pixels below floor allowed as buffer
      if (lowestFootTipY > FLOOR_HEIGHT + GROUND_COLLISION_THRESHOLD) {
          return false; // Collision detected
      }
    }

    return true;
  }, [activePin, isAirMode, isCraneDragging]); 

  // Replaced handlePoseChange with this gatekeeper function
  const validateAndApplyPoseUpdate = useCallback((
      proposedUpdates: Partial<Pose>,
      partBeingDirectlyManipulated: PartName | null, // The part changed by FK or IK target
      isEffectorDrag: boolean, // Is this an IK drag operation? - Will always be false
  ) => {
      setActivePose(prev => {
          let tentativeNextPose: Pose = { ...prev, ...proposedUpdates };

          // Validate the new pose *after* kinetic ripple (which is now just direct update)
          if (!isValidMove(
              tentativeNextPose,
              prev, // The pose before this attempt
              activePin,
              rotationStartInfo.current?.initialPinnedPos || null,
              isCraneDragging, 
              isEffectorDrag,
              partBeingDirectlyManipulated,
              isAirMode,
          )) {
              return prev; // Revert to previous pose if invalid
          }

          // If valid, push to undo stack and return new pose
          undoStack.current.push(prev);
          redoStack.current.length = 0; // Clear redo stack on new action
          return tentativeNextPose;
      });
  }, [activePin, isAirMode, isCraneDragging, isValidMove]); // Removed jointModes, jointStrengths from deps

  const handleUndo = useCallback(() => {
    if (undoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = undoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleRedo = useCallback(() => {
    if (redoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = redoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!svgRef.current) return;
    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    if (isCraneDragging && dragStartInfo.current) {
      const dx = transformedPoint.x - dragStartInfo.current.startX;
      const dy = transformedPoint.y - dragStartInfo.current.startY;

      const newRootX = dragStartInfo.current.startRootX + dx;
      const newRootY = dragStartInfo.current.startRootY + dy;

      validateAndApplyPoseUpdate({ root: { x: newRootX, y: newRootY } }, null, false);

    } else if (isAdjusting && rotatingPart && rotationStartInfo.current) { // Standard rotation drag
      const joints = getJointPositions(activePose, activePin); // Pass activePin
      const pivot = joints[rotatingPart]; 
      if (!pivot) return;

      const currentAngleDeg = Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI;
      const startAngleDeg = rotationStartInfo.current.startAngle; 

      const angleDeltaDeg = getShortestAngleDiffDeg(currentAngleDeg, startAngleDeg);

      let newRotationValue = rotationStartInfo.current.startRotationValue + angleDeltaDeg;
      const partKey = partNameToPoseKey[rotatingPart];
      const limits = JOINT_LIMITS[partKey];

      if (limits) {
        newRotationValue = Math.max(limits.min, Math.min(limits.max, newRotationValue));
      }

      validateAndApplyPoseUpdate({ [partKey]: newRotationValue }, rotatingPart, false);

    } 
    // Removed IK drag for hands/feet
  }, [isAdjusting, rotatingPart, isCraneDragging, activePose, validateAndApplyPoseUpdate, activePin]); // Added activePin to deps

  const handleMouseUp = useCallback(() => {
    setIsAdjusting(false);
    setRotatingPart(null);
    setIsCraneDragging(false);
    setEffectorPart(null); 
    setIsEffectorDragging(false); 
    rotationStartInfo.current = null;
    // FIX: Corrected assignment to use dragStartInfoInitial() which now returns `startY`.
    dragStartInfo.current = dragStartInfoInitial(); 
  }, []);

  const getInitialPinnedPos = useCallback(() => {
    const joints = getJointPositions(activePose, activePin); // Pass activePin
    let initialPinnedPos: Vector2D | null = null;

    if (activePin === 'root') {
      initialPinnedPos = joints.root;
    } else if (activePin === 'lFootTip') {
      initialPinnedPos = joints.lFootTip;
    } else if (activePin === 'rFootTip') {
      initialPinnedPos = joints.rFootTip;
    } else { // It's a PartName
      initialPinnedPos = joints[activePin];
    }

    // Clamp initialPinnedPos.y to FLOOR_HEIGHT if it's a foot tip, to prevent pinning below ground
    if (initialPinnedPos && (activePin === 'lFootTip' || activePin === 'rFootTip')) {
      initialPinnedPos = { ...initialPinnedPos, y: Math.min(initialPinnedPos.y, FLOOR_HEIGHT) };
    }
    return initialPinnedPos;
  }, [activePose, activePin]);

  const handleDoubleClickOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    // Cycle joint constraint mode: fk -> stretch -> curl -> stretch -> curl ...
    setJointModes(prev => {
      const currentMode = prev[part];
      let nextMode: JointConstraint;
      if (currentMode === 'fk') {
        nextMode = 'stretch';
      } else if (currentMode === 'stretch') {
        nextMode = 'curl';
      } else if (currentMode === 'curl') {
        nextMode = 'stretch';
      } else {
        nextMode = 'fk'; // Fallback to fk, though should not happen with current enum
      }
      return { ...prev, [part]: nextMode };
    });
  }, []);

  const handleMouseDownOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    if (!svgRef.current) return;

    setSelectedParts(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(k => next[k as PartName] = k === part);
      return next;
    });

    const joints = getJointPositions(activePose, activePin); // Pass activePin
    const pivot = joints[part]; 
    if (!pivot) return;

    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    setIsAdjusting(true);
    setRotatingPart(part);
    rotationStartInfo.current = {
      startAngle: Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI,
      startRotationValue: (activePose as any)[partNameToPoseKey[part]] || 0,
      pointerX: transformedPoint.x, pointerY: transformedPoint.y, initialPinnedPos: getInitialPinnedPos()
    };
  }, [activePose, activePin, getInitialPinnedPos]);

  // Removed applyJointMode (no kinetic behaviors)
  // Removed applyJointStrength (no kinetic behaviors)

  // Function to cycle render modes
  const cycleRenderMode = useCallback(() => {
    setRenderMode(prev => {
      if (prev === 'default') return 'wireframe';
      if (prev === 'wireframe') return 'silhouette'; // 'grayscale' render mode removed, 'silhouette' is now solid black fill
      if (prev === 'silhouette') return 'backlight'; // New transition to backlight
      if (prev === 'backlight') return 'default'; // Cycle back to default
      return 'default';
    });
  }, []);

  const cycleViewMode = useCallback(() => {
    setViewMode(prev => {
      if (prev === 'default') return 'lotte';
      if (prev === 'lotte') return 'wide';
      if (prev === 'wide') return 'mobile'; // Added mobile view
      if (prev === 'mobile') return 'zoomed'; // Cycle from mobile to zoomed
      if (prev === 'zoomed') return 'default';
      return 'default';
    });
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'v') cycleViewMode(); // Use the new cycleViewMode
      if (e.key === 'p') setActivePin(prev => {
        if (prev === PartName.Waist) return PartName.LAnkle;
        if (prev === PartName.LAnkle) return 'lFootTip'; 
        if (prev === 'lFootTip') return PartName.RAnkle; // Cycle to right ankle
        if (prev === PartName.RAnkle) return 'rFootTip'; // Cycle to right tiptoe
        if (prev === 'rFootTip') return 'root'; // Cycle to root
        return PartName.Waist; // Cycle back to Waist
      });
      // 'b' for broadcast mode removed
      if (e.key === 'r') cycleRenderMode(); // Shortcut for render mode
      if (e.key === 'z' && (e.ctrlKey || e.metaKey)) { // Ctrl+Z or Cmd+Z for undo
        e.preventDefault();
        handleUndo();
      }
      if (e.key === 'y' && (e.ctrlKey || e.metaKey)) { // Ctrl+Y or Cmd+Y for redo
        e.preventDefault();
        handleRedo();
      }
    };

    const handleResize = () => {
      setWindowSize({
        innerWidth: window.innerWidth,
        innerHeight: window.innerHeight,
      });
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('resize', handleResize); // Listen for resize events
    const timer = setTimeout(() => setShowSplash(false), 2000);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('resize', handleResize); // Clean up resize listener
      clearTimeout(timer);
    };
  }, [handleMouseMove, handleMouseUp, handleUndo, handleRedo, cycleRenderMode, cycleViewMode]);

  // Removed useEffect for global grayscale filter

  const getPinName = (pin: AnchorName) => {
    if (pin === PartName.Waist) return 'WAIST';
    if (pin === PartName.LAnkle) return 'LEFT ANKLE';
    if (pin === 'lFootTip') return 'LEFT TIPTOE';
    if (pin === PartName.RAnkle) return 'RIGHT ANKLE';
    if (pin === 'rFootTip') return 'RIGHT TIPTOE';
    if (pin === 'root') return 'ROOT';
    return 'UNKNOWN';
  };

  const getKineticModeDisplayName = (mode: JointConstraint) => {
    switch (mode) {
      case 'fk': return 'FK (Default)';
      case 'stretch': return 'KINETIC_STRETCH';
      case 'curl': return 'KINETIC_CURL';
      default: return 'UNKNOWN';
    }
  };

  const getKineticModeDisplayColorClass = (mode: JointConstraint) => {
    switch (mode) {
      case 'stretch': return 'text-accent-purple';
      case 'curl': return 'text-accent-green';
      case 'fk': return 'text-focus-ring';
      default: return 'text-white/70';
    }
  };


  const handlePartRotationWheelChange = useCallback((newValue: number) => {
    if (!primarySelectedPart) return;
    const partKey = partNameToPoseKey[primarySelectedPart];

    validateAndApplyPoseUpdate({ [partKey]: newValue }, primarySelectedPart, false);
  }, [primarySelectedPart, validateAndApplyPoseUpdate]);

  const handleBodyRotationWheelChange = useCallback((newValue: number) => {
    validateAndApplyPoseUpdate({ bodyRotation: newValue }, null, false); // No specific part, not IK
  }, [validateAndApplyPoseUpdate]);

  const allPanelRectsArray = useMemo(() => Object.values(panelRects), [panelRects]);

  return (
    <div className="w-full h-full bg-mono-darker shadow-2xl flex flex-col relative touch-none fixed inset-0 z-50 overflow-hidden text-ink font-mono">
      <div className="relative flex h-full w-full">
        {/* PIN CONTROL (Draggable Panel) */}
        <DraggablePanel
          id="pin-control-panel"
          title="PIN_CONTROL"
          x={panelRects['pin-control-panel'].x}
          y={panelRects['pin-control-panel'].y}
          minimized={panelRects['pin-control-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pin-control-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-left">
            <span className="text-white/40 text-[8px] uppercase">Pin_Location</span>
            <div className="grid grid-cols-2 gap-1">
              {([PartName.Waist, PartName.LAnkle, 'lFootTip', PartName.RAnkle, 'rFootTip', 'root'] as AnchorName[]).map(pinOption => (
                <button
                  key={pinOption}
                  onClick={() => setActivePin(pinOption)}
                  className={`text-[9px] text-left px-2 py-1 transition-all border ${
                    activePin === pinOption
                    ? 'bg-accent-red/30 border-accent-red text-accent-red' // Red for active pin
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={activePin === pinOption}
                  aria-label={`Set pin location to ${getPinName(pinOption)}`}
                >
                  {getPinName(pinOption)}
                </button>
              ))}
            </div>
          </div>

          <div className="flex flex-col gap-1 border-t border-white/10 pt-2 mt-4 items-center">
            <span className="text-white/40 uppercase text-[8px]">Body_Rotation_Angle</span>
            <RotationWheelControl
              value={activePose.bodyRotation || 0}
              min={-180} // Full 360 degree rotation range
              max={180}
              step={5}
              onChange={handleBodyRotationWheelChange}
              isDisabled={false} // Body rotation always adjustable
              className="my-2"
            />
          </div>
        </DraggablePanel>

        {/* SCALAR HUB (LEFT PANEL) - Positioned dynamically below PIN_CONTROL */}
        <DraggablePanel
          id="scalar-hub-panel"
          title="SCALAR_HUB"
          x={panelRects['scalar-hub-panel'].x}
          y={panelRects['scalar-hub-panel'].y}
          minimized={panelRects['scalar-hub-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for scalar-hub: directly below pin-control, no gap
            const pinControlRect = panelRects['pin-control-panel'];
            const newY = pinControlRect.y + pinControlRect.height; // No 16px gap
            if (panelRects['scalar-hub-panel'].y !== newY) {
              updatePanelPosition('scalar-hub-panel', pinControlRect.x, newY, panelRects['scalar-hub-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['scalar-hub-panel']}
          className="w-56"
          extraTitleContent={primarySelectedPart && <span className="text-accent-red animate-pulse text-[8px]">ACTIVE_PIVOT</span>}
        >
          {/* SCALAR_INFO_PANE */}
          <div className="bg-white/5 p-2 rounded border border-white/10 mb-3 flex flex-col gap-2">
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full" style={{ backgroundColor: primarySelectedPart ? COLORS_BY_CATEGORY[getPartCategory(primarySelectedPart)] : '#9CA3AF' }}></span>
              <span className="text-white/70 text-[9px] uppercase font-bold">
                {primarySelectedPart ? getPartCategoryDisplayName(primarySelectedPart) : 'WHOLE FIGURE'}
              </span>
            </div>
            <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
              <span className="text-white/40 uppercase text-[8px]">Rotation_Angle</span>
              <RotationWheelControl
                value={primarySelectedPart ? activePose[partNameToPoseKey[primarySelectedPart]] || 0 : 0}
                min={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.min || -180 : -180}
                max={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.max || 180 : 180}
                step={5}
                onChange={handlePartRotationWheelChange}
                isDisabled={!primarySelectedPart}
                className="my-2"
              />
            </div>
            {primarySelectedPart && (
              <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
                <span className="text-white/40 uppercase text-[8px]">Kinetic_Mode</span>
                <button
                  // FIX: Removed incorrect type assertion and direct call to handleDoubleClickOnPart.
                  // The button now directly cycles the joint modes based on the primarySelectedPart.
                  onClick={() => {
                    if (primarySelectedPart) {
                      setJointModes(prev => {
                        const currentMode = prev[primarySelectedPart];
                        let nextMode: JointConstraint;
                        if (currentMode === 'fk') {
                          nextMode = 'stretch';
                        } else if (currentMode === 'stretch') {
                          nextMode = 'curl';
                        } else if (currentMode === 'curl') {
                          nextMode = 'stretch';
                        } else {
                          nextMode = 'fk'; // Fallback to fk
                        }
                        return { ...prev, [primarySelectedPart]: nextMode };
                      });
                    }
                  }}
                  disabled={!primarySelectedPart}
                  className={`w-full text-[9px] font-bold text-center px-2 py-1 transition-all border ${
                    !primarySelectedPart
                      ? 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                      : `bg-white/10 border-white/20 hover:bg-white/20 ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`
                  }`}
                  aria-label={`Toggle Kinetic Mode for ${getPartCategoryDisplayName(primarySelectedPart)}. Current mode: ${getKineticModeDisplayName(jointModes[primarySelectedPart])}`}
                  aria-pressed={jointModes[primarySelectedPart] !== 'fk'}
                >
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </button>
              </div>
            )}
          </div>

          {/* Undo/Redo Buttons */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex justify-between gap-2">
            <button
              onClick={handleUndo}
              disabled={undoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                undoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Undo last action"
            >
              UNDO
            </button>
            <button
              onClick={handleRedo}
              disabled={redoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                redoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Redo last action"
            >
              REDO
            </button>
          </div>

          {/* Optics Mode Selector */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex flex-col gap-1">
            <span className="text-white/40 text-[8px] uppercase">Optics_Mode</span>
            <div className="flex flex-col gap-1">
              {(['default', 'wireframe', 'silhouette', 'backlight'] as RenderMode[]).map(mode => (
                <button
                  key={mode}
                  onClick={() => setRenderMode(mode)}
                  className={`text-[9px] text-center px-2 py-1 transition-all border ${
                    renderMode === mode 
                    ? 'bg-selection/30 border-selection text-selection' 
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={renderMode === mode}
                  aria-label={`Set render mode to ${mode === 'silhouette' ? 'Monochrome Fill' : mode === 'backlight' ? 'Backlight' : mode.toUpperCase()}`}
                >
                  {mode === 'silhouette' ? 'MONOCHROME_FILL' : mode === 'backlight' ? 'BACKLIGHT' : mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        </DraggablePanel>

        {/* SYSTEM STATUS (RIGHT PANEL - Pin Box and Active Limb Box) */}
        <DraggablePanel
          id="system-status-panel"
          title="MONITOR_O1"
          x={panelRects['system-status-panel'].x}
          y={panelRects['system-status-panel'].y}
          minimized={panelRects['system-status-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['system-status-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">OPTICS_VIEW</span>
            <div className="grid grid-cols-2 gap-1 items-center">
              <span>MODE:</span> 
              <span className="text-accent-green text-right">{viewMode.toUpperCase()}</span>
              {/* View mode selector buttons */}
              {(['default', 'lotte', 'wide', 'mobile', 'zoomed'] as ViewMode[]).map(_mode => (
                <button
                  key={_mode}
                  onClick={() => setViewMode(_mode)}
                  className={`col-span-1 text-[9px] text-center px-1 py-0.5 transition-all border ${
                    viewMode === _mode
                      ? 'bg-accent-green/30 border-accent-green text-accent-green'
                      : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={viewMode === _mode}
                  aria-label={`Set view mode to ${_mode.toUpperCase()}`}
                >
                  {_mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIN_CONFIGURATION</span>
            <div className="flex gap-4 justify-between w-full"><span>STATE:</span> <span className="text-accent-red">{getPinName(activePin)}</span></div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIVOT_STATUS</span>
            <div className="flex gap-4 justify-between w-full"><span>ACTIVE:</span> <span className="text-focus-ring">{primarySelectedPart || 'NONE'}</span></div>
          </div>

          {primarySelectedPart && (
            <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
              <span className="text-white/40 text-[8px] mb-1">KINETIC_MODE</span>
              <div className="flex gap-4 justify-between w-full">
                <span>STATE:</span> 
                <span className={`text-[9px] font-bold ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`}>
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </span>
              </div>
            </div>
          )}

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">RENDER_MODE</span>
            <div className="flex gap-4 justify-between w-full"><span>MODE:</span> <span className="text-focus-ring">{renderMode.toUpperCase()}</span></div>
          </div>
        </DraggablePanel>

        {/* COMMAND LOG (New Draggable Panel) */}
        <DraggablePanel
          id="command-log-panel"
          title="COMMAND_LOG"
          x={panelRects['command-log-panel'].x}
          y={panelRects['command-log-panel'].y}
          minimized={panelRects['command-log-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for command-log: directly below system-status, no gap
            const systemStatusRect = panelRects['system-status-panel'];
            const newY = systemStatusRect.y + systemStatusRect.height; 
            if (panelRects['command-log-panel'].y !== newY) {
              updatePanelPosition('command-log-panel', systemStatusRect.x, newY, panelRects['command-log-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['command-log-panel']}
          className="w-56"
        >
           <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest">
            <span className="text-white/30 mb-1 border-b border-white/10 pb-1">COMMAND_UNIT</span>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[V]</span> <span>Optics</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[P]</span> <span>Pin</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[R]</span> <span>Render Mode</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Z]</span> <span>Undo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Y]</span> <span>Redo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DRAG</span> <span>Posing</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DBL-CLK</span> <span>Kinetic Mode</span></div>
            <div className="mt-2 text-white/30 border-b border-white/10 pb-1">KINETIC_LEGEND</div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.PURPLE_STRETCH}}></span> <span className="text-accent-purple">STRETCH</span></div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.GREEN_CURL}}></span> <span className="text-accent-green">CURL</span></div>
          </div>
        </DraggablePanel>

        {/* POSE DATA TERMINAL (New Draggable Panel) */}
        <DraggablePanel
          id="pose-data-terminal-panel"
          title="POSE_DATA_TERMINAL"
          x={panelRects['pose-data-terminal-panel'].x}
          y={panelRects['pose-data-terminal-panel'].y}
          minimized={panelRects['pose-data-terminal-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for pose-data-terminal: directly below command-log, no gap
            const commandLogRect = panelRects['command-log-panel'];
            const newY = commandLogRect.y + commandLogRect.height; 
            if (panelRects['pose-data-terminal-panel'].y !== newY) {
              updatePanelPosition('pose-data-terminal-panel', commandLogRect.x, newY, panelRects['pose-data-terminal-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pose-data-terminal-panel']}
          className="w-56"
        >
          <div className="text-white/70 text-[8px] whitespace-pre-wrap break-all h-full overflow-y-auto custom-scrollbar">
            {poseToString(activePose)}
          </div>
        </DraggablePanel>

        {/* This div wraps the entire mannequin rendering area, no specific z-index here */}
        <div className="w-full h-full bg-selection-super-light bg-triangle-grid flex items-center justify-center relative">
          <Scanlines />
          {showSplash && (
            <div className="absolute top-[8%] left-0 right-0 z-30 flex items-center justify-center pointer-events-none">
              <h1 className="text-6xl font-archaic text-paper/80 animate-terminal-boot tracking-widest uppercase">BITRUVIUS</h1>
            </div>
          )}

          <svg 
            ref={svgRef} 
            width="100%" 
            height="100%" 
            viewBox={autoViewBox} 
            className="overflow-visible relative z-10" 
          >
            <SystemGuides floorY={FLOOR_HEIGHT} /> 
            <g>
              <Mannequin
                pose={activePose}
                showOverlay={true}
                selectedParts={selectedParts}
                visibility={visibility}
                pin={activePin}
                className="text-black"
                onMouseDownOnPart={handleMouseDownOnPart}
                onDoubleClickOnPart={handleDoubleClickOnPart} // Reintroduced
                onMouseDownOnRoot={(e) => { 
                  e.stopPropagation(); 
                  setIsCraneDragging(true); 
                  // FIX: Corrected 'y' to 'startY' to match the dragStartInfo type.
                  dragStartInfo.current = { startX: e.clientX, startY: e.clientY, startRootX: activePose.root.x, startRootY: activePose.root.y }; 
                }}
                jointModes={jointModes} // Reintroduced
                renderMode={renderMode}
              />
            </g>
          </svg>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import { Pose, PartName, PartSelection, PartVisibility, AnchorName, partNameToPoseKey, PARENT_MAP, CHILD_MAP, LIMB_SEQUENCES, JointConstraint, RenderMode, Vector2D, ViewMode } from './types';
import { RESET_POSE, FLOOR_HEIGHT, SCALE_FACTOR, JOINT_LIMITS, FLOOR_SINK_BUFFER, GROUND_SINK_REMAINING_PROPORTION, ANATOMY, GROUND_STRIP_HEIGHT } from './constants'; 
import { getJointPositions, solveArmIK, solveLegIK, getShortestAngleDiffDeg } from './utils/kinematics';
import { Scanlines, SystemGuides } from './components/SystemGrid';
import { Mannequin, getPartCategory, getPartCategoryDisplayName } from './components/Mannequin'; 
import { DraggablePanel } from './components/DraggablePanel';
import { COLORS_BY_CATEGORY, COLORS } from './components/Bone'; // Import COLORS_BY_CATEGORY and COLORS for kinetic mode display
import { poseToString } from './utils/pose-parser'; // Import poseToString
import { RotationWheelControl } from './components/RotationWheelControl'; // Import RotationWheelControl

interface PanelRect {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  minimized: boolean;
}

const App: React.FC = () => {
  const [activePose, setActivePose] = useState<Pose>(RESET_POSE);
  const undoStack = useRef<Pose[]>([]);
  // FIX: Moved `redoStack` declaration before its first usage.
  const redoStack = useRef<Pose[]>([]); 
  redoStack.current = []; // Clear redo stack on mount


  const [viewMode, setViewMode] = useState<ViewMode>('default');
  const [activePin, setActivePin] = useState<AnchorName>(PartName.Waist); // Default to Waist
  const [renderMode, setRenderMode] = useState<RenderMode>('default');

  const [selectedParts, setSelectedParts] = useState<PartSelection>(() => {
    const initialSelection: PartSelection = Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: false }), {} as PartSelection);
    initialSelection[PartName.Waist] = true; 
    return initialSelection;
  });

  const [visibility] = useState<PartVisibility>(() => Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: true }), {} as PartVisibility));

  // Joint modes state - Reintroduced for kinetic behaviors
  const [jointModes, setJointModes] = useState<Record<PartName, JointConstraint>>(() => 
    Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: 'fk' }), {} as Record<PartName, JointConstraint>)
  );

  // Joint strengths removed (no kinetic behaviors)
  // Broadcast mode removed (no kinetic behaviors)

  const [isAdjusting, setIsAdjusting] = useState(false); // For standard rotation
  const [rotatingPart, setRotatingPart] = useState<PartName | null>(null);
  const rotationStartInfo = useRef<{ 
    startAngle: number; 
    startRotationValue: number; 
    pointerX: number; 
    pointerY: number;
    initialPinnedPos: Vector2D | null;
  } | null>(null);

  // IK drag states removed (no IK)
  const [isEffectorDragging, setIsEffectorDragging] = useState(false); // Kept for isValidMove check, always false
  const [effectorPart, setEffectorPart] = useState<PartName | null>(null); // Kept for isValidMove check, always null

  const svgRef = useRef<SVGSVGElement>(null); 
  // Crane states removed (no crane)
  const [isCraneActive] = useState(false); // Always false
  const [isCraneDragging, setIsCraneDragging] = useState(false); // For dragging root
  const dragStartInfo = useRef<{ startX: number; startY: number; startRootX: number; startRootY: number } | null>(dragStartInfoInitial());

  // Function to provide initial dragStartInfo value, preventing it from being null
  function dragStartInfoInitial() {
    // FIX: Corrected 'y' to 'startY' to match the RefObject's type definition.
    return { startX: 0, startY: 0, startRootX: 0, startRootY: 0 };
  }

  const [showSplash, setShowSplash] = useState(true);
  const [isAirMode] = useState(false); // Always false

  // State to hold window dimensions for responsive viewBox calculation
  const [windowSize, setWindowSize] = useState({
    innerWidth: window.innerWidth,
    innerHeight: window.innerHeight,
  });

  // Panel Z-index management
  const [panelZIndices, setPanelZIndices] = useState<Record<string, number>>({
    'pin-control-panel': 102, // Higher Z-index
    'scalar-hub-panel': 101, // Higher Z-index
    'system-status-panel': 100, // Higher Z-index
    'command-log-panel': 99, 
    'pose-data-terminal-panel': 98, // New panel
  });
  const nextZIndex = useRef<number>(103); // Start higher than initial values

  const bringPanelToFront = useCallback((id: string) => {
    setPanelZIndices(prev => {
      const newZIndices = { ...prev };
      newZIndices[id] = nextZIndex.current++;
      return newZIndices;
    });
  }, []);

  // --- Panel Position/Size Management ---
  const [panelRects, setPanelRects] = useState<Record<string, PanelRect>>({
    'pin-control-panel': { id: 'pin-control-panel', x: 16, y: 16, width: 224, height: 230, minimized: false }, // Adjusted height to accommodate pin rotation wheel
    'scalar-hub-panel': { id: 'scalar-hub-panel', x: 16, y: 16 + 230, width: 224, height: 250, minimized: false }, 
    'system-status-panel': { id: 'system-status-panel', x: window.innerWidth - 224 - 16, y: 16, width: 224, height: 180, minimized: false }, 
    'command-log-panel': { id: 'command-log-panel', x: window.innerWidth - 224 - 16, y: 16 + 180, width: 224, height: 180, minimized: false }, 
    'pose-data-terminal-panel': { id: 'pose-data-terminal-panel', x: window.innerWidth - 224 - 16, y: 16 + 180 + 180, width: 224, height: 150, minimized: false }, 
  });

  const updatePanelRect = useCallback((id: string, newRect: Omit<PanelRect, 'x' | 'y'>) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.width !== newRect.width || existingRect.height !== newRect.height || existingRect.minimized !== newRect.minimized) {
        return { ...prev, [id]: { ...existingRect, ...newRect } };
      }
      return prev;
    });
  }, []);

  const updatePanelPosition = useCallback((id: string, newX: number, newY: number, minimized: boolean) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.x !== newX || existingRect.y !== newY || existingRect.minimized !== minimized) {
        return { ...prev, [id]: { ...existingRect, x: newX, y: newY, minimized: minimized } };
      }
      return prev;
    });
  }, []);
  // --- End Panel Position/Size Management ---

  const primarySelectedPart = useMemo(() => {
    return (Object.entries(selectedParts).find(([p, sel]) => sel)?.[0]) as PartName | undefined;
  }, [selectedParts]);

  // Dynamically calculate viewBox based on viewMode and windowSize
  const autoViewBox = useMemo(() => {
    const configs = {
      zoomed: { x: -900, y: 1950, w: 1800, h: 1550 },
      default: { x: -1112.5, y: 1287.5, w: 2225, h: 2212.5 },
      lotte: { x: -1325, y: 625, w: 2650, h: 2875 },
      wide: { x: -1750, y: -700, w: 3500, h: 4200 },
    };

    if (viewMode === 'mobile') {
      const screenAspectRatio = windowSize.innerWidth / windowSize.innerHeight;

      // Calculate the approximate full height of the mannequin in SVG units
      const mannequinIntrinsicHeight = (
        ANATOMY.HEAD +
        ANATOMY.HEAD_NECK_GAP_OFFSET +
        ANATOMY.COLLAR +
        ANATOMY.TORSO +
        ANATOMY.WAIST +
        ANATOMY.LEG_UPPER +
        ANATOMY.LEG_LOWER +
        ANATOMY.FOOT
      );

      // Define desired vertical content height including some padding
      const verticalPaddingRatio = 0.20; // 20% padding above and below mannequin
      const contentHeightInSVGUnits = mannequinIntrinsicHeight * (1 + verticalPaddingRatio);

      const viewBoxHeight = contentHeightInSVGUnits;
      const viewBoxWidth = viewBoxHeight * screenAspectRatio;

      // Position the floor (FLOOR_HEIGHT) slightly above the very bottom of the viewBox
      const groundPlaneBuffer = GROUND_STRIP_HEIGHT * 1.5; // Ensure ground strip is visible + some buffer
      const desiredViewBoxBottom = FLOOR_HEIGHT + groundPlaneBuffer;
      const viewBoxY = desiredViewBoxBottom - viewBoxHeight;
      const viewBoxX = -viewBoxWidth / 2; // Center horizontally

      return `${viewBoxX} ${viewBoxY} ${viewBoxWidth} ${viewBoxHeight}`;

    } else {
      const c = configs[viewMode];
      return `${c.x} ${c.y} ${c.w} ${c.h}`;
    }
  }, [viewMode, windowSize.innerWidth, windowSize.innerHeight]);

  // --- Physics Validation Logic ---
  const isValidMove = useCallback((
    potentialPose: Pose,
    originalPose: Pose,
    activePin: AnchorName,
    initialPinnedPos: Vector2D | null,
    isCraneDragging: boolean,
    isEffectorDragging: boolean, // Will always be false now
    partBeingRotated: PartName | null,
    isAirMode: boolean, // Will always be false now
  ): boolean => {
    if (isAirMode) return true; // No grounding/pinning checks in air mode

    const potentialJoints = getJointPositions(potentialPose, activePin); // Pass activePin
    const originalJoints = getJointPositions(originalPose, activePin); // Pass activePin

    // 1. Check Pin Immovability
    if (!isCraneDragging && initialPinnedPos && activePin) {
        const currentPinnedPosInPotentialPose = potentialJoints[activePin as keyof typeof potentialJoints];
        if (currentPinnedPosInPotentialPose) {
            const dx = currentPinnedPosInPotentialPose.x - initialPinnedPos.x;
            const dy = currentPinnedPosInPotentialPose.y - initialPinnedPos.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            const PIN_TOLERANCE = 2; // Pixels
            if (distance > PIN_TOLERANCE) {
                return false; // Pin moved too much
            }
        }
    }

    // 2. Check Ground Collision
    const isFootRelatedPart = (part: PartName | null) =>
      part === PartName.LAnkle || part === PartName.RAnkle || part === PartName.LSkin || part === PartName.RSkin; 

    const relevantToGrounding = isCraneDragging || isEffectorDragging || isFootRelatedPart(partBeingRotated);

    if (relevantToGrounding) {
      const lFootTipY = potentialJoints.lFootTip?.y || -Infinity;
      const rFootTipY = potentialJoints.rFootTip?.y || -Infinity;
      const lowestFootTipY = Math.max(lFootTipY, rFootTipY);

      const GROUND_COLLISION_THRESHOLD = 2; // Pixels below floor allowed as buffer
      if (lowestFootTipY > FLOOR_HEIGHT + GROUND_COLLISION_THRESHOLD) {
          return false; // Collision detected
      }
    }

    return true;
  }, [activePin, isAirMode, isCraneDragging]); 

  // Replaced handlePoseChange with this gatekeeper function
  const validateAndApplyPoseUpdate = useCallback((
      proposedUpdates: Partial<Pose>,
      partBeingDirectlyManipulated: PartName | null, // The part changed by FK or IK target
      isEffectorDrag: boolean, // Is this an IK drag operation? - Will always be false
  ) => {
      setActivePose(prev => {
          let tentativeNextPose: Pose = { ...prev, ...proposedUpdates };

          // Validate the new pose *after* kinetic ripple (which is now just direct update)
          if (!isValidMove(
              tentativeNextPose,
              prev, // The pose before this attempt
              activePin,
              rotationStartInfo.current?.initialPinnedPos || null,
              isCraneDragging, 
              isEffectorDrag,
              partBeingDirectlyManipulated,
              isAirMode,
          )) {
              return prev; // Revert to previous pose if invalid
          }

          // If valid, push to undo stack and return new pose
          undoStack.current.push(prev);
          redoStack.current.length = 0; // Clear redo stack on new action
          return tentativeNextPose;
      });
  }, [activePin, isAirMode, isCraneDragging, isValidMove]); // Removed jointModes, jointStrengths from deps

  const handleUndo = useCallback(() => {
    if (undoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = undoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleRedo = useCallback(() => {
    if (redoStack.current.length > 0) {
      setActivePose(prev => {
        // FIX: The redo stack should push the *current* state before popping the next state.
        // It was incorrectly pushing 'prev' from outside the scope of the redo action.
        undoStack.current.push(prev); // Push current state to undo stack before moving forward
        const nextPose = redoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!svgRef.current) return;
    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    if (isCraneDragging && dragStartInfo.current) {
      const dx = transformedPoint.x - dragStartInfo.current.startX;
      const dy = transformedPoint.y - dragStartInfo.current.startY;

      const newRootX = dragStartInfo.current.startRootX + dx;
      const newRootY = dragStartInfo.current.startRootY + dy;

      validateAndApplyPoseUpdate({ root: { x: newRootX, y: newRootY } }, null, false);

    } else if (isAdjusting && rotatingPart && rotationStartInfo.current) { // Standard rotation drag
      const joints = getJointPositions(activePose, activePin); // Pass activePin
      const pivot = joints[rotatingPart]; 
      if (!pivot) return;

      const currentAngleDeg = Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI;
      const startAngleDeg = rotationStartInfo.current.startAngle; 

      const angleDeltaDeg = getShortestAngleDiffDeg(currentAngleDeg, startAngleDeg);

      let newRotationValue = rotationStartInfo.current.startRotationValue + angleDeltaDeg;
      const partKey = partNameToPoseKey[rotatingPart];
      const limits = JOINT_LIMITS[partKey];

      if (limits) {
        newRotationValue = Math.max(limits.min, Math.min(limits.max, newRotationValue));
      }

      validateAndApplyPoseUpdate({ [partKey]: newRotationValue }, rotatingPart, false);

    } 
    // Removed IK drag for hands/feet
  }, [isAdjusting, rotatingPart, isCraneDragging, activePose, validateAndApplyPoseUpdate, activePin]); // Added activePin to deps

  const handleMouseUp = useCallback(() => {
    setIsAdjusting(false);
    setRotatingPart(null);
    setIsCraneDragging(false);
    setEffectorPart(null); 
    setIsEffectorDragging(false); 
    rotationStartInfo.current = null;
    // FIX: Corrected assignment to use dragStartInfoInitial() which now returns `startY`.
    dragStartInfo.current = dragStartInfoInitial(); 
  }, []);

  const getInitialPinnedPos = useCallback(() => {
    const joints = getJointPositions(activePose, activePin); // Pass activePin
    let initialPinnedPos: Vector2D | null = null;

    if (activePin === 'root') {
      initialPinnedPos = joints.root;
    } else if (activePin === 'lFootTip') {
      initialPinnedPos = joints.lFootTip;
    } else if (activePin === 'rFootTip') {
      initialPinnedPos = joints.rFootTip;
    } else { // It's a PartName
      initialPinnedPos = joints[activePin];
    }

    // Clamp initialPinnedPos.y to FLOOR_HEIGHT if it's a foot tip, to prevent pinning below ground
    if (initialPinnedPos && (activePin === 'lFootTip' || activePin === 'rFootTip')) {
      initialPinnedPos = { ...initialPinnedPos, y: Math.min(initialPinnedPos.y, FLOOR_HEIGHT) };
    }
    return initialPinnedPos;
  }, [activePose, activePin]);

  const handleDoubleClickOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    // Cycle joint constraint mode: fk -> stretch -> curl -> stretch -> curl ...
    setJointModes(prev => {
      const currentMode = prev[part];
      let nextMode: JointConstraint;
      if (currentMode === 'fk') {
        nextMode = 'stretch';
      } else if (currentMode === 'stretch') {
        nextMode = 'curl';
      } else if (currentMode === 'curl') {
        nextMode = 'stretch';
      } else {
        nextMode = 'fk'; // Fallback to fk, though should not happen with current enum
      }
      return { ...prev, [part]: nextMode };
    });
  }, []);

  const handleMouseDownOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    if (!svgRef.current) return;

    setSelectedParts(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(k => next[k as PartName] = k === part);
      return next;
    });

    const joints = getJointPositions(activePose, activePin); // Pass activePin
    const pivot = joints[part]; 
    if (!pivot) return;

    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    setIsAdjusting(true);
    setRotatingPart(part);
    rotationStartInfo.current = {
      startAngle: Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI,
      startRotationValue: (activePose as any)[partNameToPoseKey[part]] || 0,
      pointerX: transformedPoint.x, pointerY: transformedPoint.y, initialPinnedPos: getInitialPinnedPos()
    };
  }, [activePose, activePin, getInitialPinnedPos]);

  // Removed applyJointMode (no kinetic behaviors)
  // Removed applyJointStrength (no kinetic behaviors)

  // Function to cycle render modes
  const cycleRenderMode = useCallback(() => {
    setRenderMode(prev => {
      if (prev === 'default') return 'wireframe';
      if (prev === 'wireframe') return 'silhouette'; // 'grayscale' render mode removed, 'silhouette' is now solid black fill
      if (prev === 'silhouette') return 'backlight'; // New transition to backlight
      if (prev === 'backlight') return 'default'; // Cycle back to default
      return 'default';
    });
  }, []);

  const cycleViewMode = useCallback(() => {
    setViewMode(prev => {
      if (prev === 'default') return 'lotte';
      if (prev === 'lotte') return 'wide';
      if (prev === 'wide') return 'mobile'; // Added mobile view
      if (prev === 'mobile') return 'zoomed'; // Cycle from mobile to zoomed
      if (prev === 'zoomed') return 'default';
      return 'default';
    });
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'v') cycleViewMode(); // Use the new cycleViewMode
      if (e.key === 'p') setActivePin(prev => {
        if (prev === PartName.Waist) return PartName.LAnkle;
        if (prev === PartName.LAnkle) return 'lFootTip'; 
        if (prev === 'lFootTip') return PartName.RAnkle; // Cycle to right ankle
        if (prev === PartName.RAnkle) return 'rFootTip'; // Cycle to right tiptoe
        if (prev === 'rFootTip') return 'root'; // Cycle to root
        return PartName.Waist; // Cycle back to Waist
      });
      // 'b' for broadcast mode removed
      if (e.key === 'r') cycleRenderMode(); // Shortcut for render mode
      if (e.key === 'z' && (e.ctrlKey || e.metaKey)) { // Ctrl+Z or Cmd+Z for undo
        e.preventDefault();
        handleUndo();
      }
      if (e.key === 'y' && (e.ctrlKey || e.metaKey)) { // Ctrl+Y or Cmd+Y for redo
        e.preventDefault();
        handleRedo();
      }
    };

    const handleResize = () => {
      setWindowSize({
        innerWidth: window.innerWidth,
        innerHeight: window.innerHeight,
      });
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('resize', handleResize); // Listen for resize events
    const timer = setTimeout(() => setShowSplash(false), 2000);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('resize', handleResize); // Clean up resize listener
      clearTimeout(timer);
    };
  }, [handleMouseMove, handleMouseUp, handleUndo, handleRedo, cycleRenderMode, cycleViewMode]);

  // Removed useEffect for global grayscale filter

  const getPinName = (pin: AnchorName) => {
    if (pin === PartName.Waist) return 'WAIST';
    if (pin === PartName.LAnkle) return 'LEFT ANKLE';
    if (pin === 'lFootTip') return 'LEFT TIPTOE';
    if (pin === PartName.RAnkle) return 'RIGHT ANKLE';
    if (pin === 'rFootTip') return 'RIGHT TIPTOE';
    if (pin === 'root') return 'ROOT';
    return 'UNKNOWN';
  };

  const getKineticModeDisplayName = (mode: JointConstraint) => {
    switch (mode) {
      case 'fk': return 'FK (Default)';
      case 'stretch': return 'KINETIC_STRETCH';
      case 'curl': return 'KINETIC_CURL';
      default: return 'UNKNOWN';
    }
  };

  const getKineticModeDisplayColorClass = (mode: JointConstraint) => {
    switch (mode) {
      case 'stretch': return 'text-accent-purple';
      case 'curl': return 'text-accent-green';
      case 'fk': return 'text-focus-ring';
      default: return 'text-white/70';
    }
  };


  const handlePartRotationWheelChange = useCallback((newValue: number) => {
    if (!primarySelectedPart) return;
    const partKey = partNameToPoseKey[primarySelectedPart];

    validateAndApplyPoseUpdate({ [partKey]: newValue }, primarySelectedPart, false);
  }, [primarySelectedPart, validateAndApplyPoseUpdate]);

  const handleBodyRotationWheelChange = useCallback((newValue: number) => {
    validateAndApplyPoseUpdate({ bodyRotation: newValue }, null, false); // No specific part, not IK
  }, [validateAndApplyPoseUpdate]);

  const allPanelRectsArray = useMemo(() => Object.values(panelRects), [panelRects]);

  return (
    <div className="w-full h-full bg-mono-darker shadow-2xl flex flex-col relative touch-none fixed inset-0 z-50 overflow-hidden text-ink font-mono">
      <div className="relative flex h-full w-full">
        {/* PIN CONTROL (Draggable Panel) */}
        <DraggablePanel
          id="pin-control-panel"
          title="PIN_CONTROL"
          x={panelRects['pin-control-panel'].x}
          y={panelRects['pin-control-panel'].y}
          minimized={panelRects['pin-control-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pin-control-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-left">
            <span className="text-white/40 text-[8px] uppercase">Pin_Location</span>
            <div className="grid grid-cols-2 gap-1">
              {([PartName.Waist, PartName.LAnkle, 'lFootTip', PartName.RAnkle, 'rFootTip', 'root'] as AnchorName[]).map(pinOption => (
                <button
                  key={pinOption}
                  onClick={() => setActivePin(pinOption)}
                  className={`text-[9px] text-left px-2 py-1 transition-all border ${
                    activePin === pinOption
                    ? 'bg-accent-red/30 border-accent-red text-accent-red' // Red for active pin
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={activePin === pinOption}
                  aria-label={`Set pin location to ${getPinName(pinOption)}`}
                >
                  {getPinName(pinOption)}
                </button>
              ))}
            </div>
          </div>

          <div className="flex flex-col gap-1 border-t border-white/10 pt-2 mt-4 items-center">
            <span className="text-white/40 uppercase text-[8px]">Body_Rotation_Angle</span>
            <RotationWheelControl
              value={activePose.bodyRotation || 0}
              min={-180} // Full 360 degree rotation range
              max={180}
              step={5}
              onChange={handleBodyRotationWheelChange}
              isDisabled={false} // Body rotation always adjustable
              className="my-2"
            />
          </div>
        </DraggablePanel>

        {/* SCALAR HUB (LEFT PANEL) - Positioned dynamically below PIN_CONTROL */}
        <DraggablePanel
          id="scalar-hub-panel"
          title="SCALAR_HUB"
          x={panelRects['scalar-hub-panel'].x}
          y={panelRects['scalar-hub-panel'].y}
          minimized={panelRects['scalar-hub-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for scalar-hub: directly below pin-control, no gap
            const pinControlRect = panelRects['pin-control-panel'];
            const newY = pinControlRect.y + pinControlRect.height; // No 16px gap
            if (panelRects['scalar-hub-panel'].y !== newY) {
              updatePanelPosition('scalar-hub-panel', pinControlRect.x, newY, panelRects['scalar-hub-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['scalar-hub-panel']}
          className="w-56"
          extraTitleContent={primarySelectedPart && <span className="text-accent-red animate-pulse text-[8px]">ACTIVE_PIVOT</span>}
        >
          {/* SCALAR_INFO_PANE */}
          <div className="bg-white/5 p-2 rounded border border-white/10 mb-3 flex flex-col gap-2">
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full" style={{ backgroundColor: primarySelectedPart ? COLORS_BY_CATEGORY[getPartCategory(primarySelectedPart)] : '#9CA3AF' }}></span>
              <span className="text-white/70 text-[9px] uppercase font-bold">
                {primarySelectedPart ? getPartCategoryDisplayName(primarySelectedPart) : 'WHOLE FIGURE'}
              </span>
            </div>
            <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
              <span className="text-white/40 uppercase text-[8px]">Rotation_Angle</span>
              <RotationWheelControl
                value={primarySelectedPart ? activePose[partNameToPoseKey[primarySelectedPart]] || 0 : 0}
                min={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.min || -180 : -180}
                max={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.max || 180 : 180}
                step={5}
                onChange={handlePartRotationWheelChange}
                isDisabled={!primarySelectedPart}
                className="my-2"
              />
            </div>
            {primarySelectedPart && (
              <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
                <span className="text-white/40 uppercase text-[8px]">Kinetic_Mode</span>
                <button
                  // FIX: Removed incorrect type assertion and direct call to handleDoubleClickOnPart.
                  // The button now directly cycles the joint modes based on the primarySelectedPart.
                  onClick={() => {
                    if (primarySelectedPart) {
                      setJointModes(prev => {
                        const currentMode = prev[primarySelectedPart];
                        let nextMode: JointConstraint;
                        if (currentMode === 'fk') {
                          nextMode = 'stretch';
                        } else if (currentMode === 'stretch') {
                          nextMode = 'curl';
                        } else if (currentMode === 'curl') {
                          nextMode = 'stretch';
                        } else {
                          nextMode = 'fk'; // Fallback to fk
                        }
                        return { ...prev, [primarySelectedPart]: nextMode };
                      });
                    }
                  }}
                  disabled={!primarySelectedPart}
                  className={`w-full text-[9px] font-bold text-center px-2 py-1 transition-all border ${
                    !primarySelectedPart
                      ? 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                      : `bg-white/10 border-white/20 hover:bg-white/20 ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`
                  }`}
                  aria-label={`Toggle Kinetic Mode for ${getPartCategoryDisplayName(primarySelectedPart)}. Current mode: ${getKineticModeDisplayName(jointModes[primarySelectedPart])}`}
                  aria-pressed={jointModes[primarySelectedPart] !== 'fk'}
                >
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </button>
              </div>
            )}
          </div>

          {/* Undo/Redo Buttons */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex justify-between gap-2">
            <button
              onClick={handleUndo}
              disabled={undoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                undoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Undo last action"
            >
              UNDO
            </button>
            <button
              onClick={handleRedo}
              disabled={redoStack.current.length === 0}
              className={`flex-1 text-[9px] px-2 py-1 border ${
                redoStack.current.length > 0 
                ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
              } transition-all`}
              aria-label="Redo last action"
            >
              REDO
            </button>
          </div>

          {/* Optics Mode Selector */}
          <div className="border-t border-white/10 pt-2 mt-4 w-full flex flex-col gap-1">
            <span className="text-white/40 text-[8px] uppercase">Optics_Mode</span>
            <div className="flex flex-col gap-1">
              {(['default', 'wireframe', 'silhouette', 'backlight'] as RenderMode[]).map(mode => (
                <button
                  key={mode}
                  onClick={() => setRenderMode(mode)}
                  className={`text-[9px] text-center px-2 py-1 transition-all border ${
                    renderMode === mode 
                    ? 'bg-selection/30 border-selection text-selection' 
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={renderMode === mode}
                  aria-label={`Set render mode to ${mode === 'silhouette' ? 'Monochrome Fill' : mode === 'backlight' ? 'Backlight' : mode.toUpperCase()}`}
                >
                  {mode === 'silhouette' ? 'MONOCHROME_FILL' : mode === 'backlight' ? 'BACKLIGHT' : mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        </DraggablePanel>

        {/* SYSTEM STATUS (RIGHT PANEL - Pin Box and Active Limb Box) */}
        <DraggablePanel
          id="system-status-panel"
          title="MONITOR_O1"
          x={panelRects['system-status-panel'].x}
          y={panelRects['system-status-panel'].y}
          minimized={panelRects['system-status-panel'].minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['system-status-panel']}
          className="w-56"
        >
          <div className="flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">OPTICS_VIEW</span>
            <div className="grid grid-cols-2 gap-1 items-center">
              <span>MODE:</span> 
              <span className="text-accent-green text-right">{viewMode.toUpperCase()}</span>
              {/* View mode selector buttons */}
              {(['default', 'lotte', 'wide', 'mobile', 'zoomed'] as ViewMode[]).map(_mode => (
                <button
                  key={_mode}
                  onClick={() => setViewMode(_mode)}
                  className={`col-span-1 text-[9px] text-center px-1 py-0.5 transition-all border ${
                    viewMode === _mode
                      ? 'bg-accent-green/30 border-accent-green text-accent-green'
                      : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={viewMode === _mode}
                  aria-label={`Set view mode to ${_mode.toUpperCase()}`}
                >
                  {_mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIN_CONFIGURATION</span>
            <div className="flex gap-4 justify-between w-full"><span>STATE:</span> <span className="text-accent-red">{getPinName(activePin)}</span></div>
          </div>

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">PIVOT_STATUS</span>
            <div className="flex gap-4 justify-between w-full"><span>ACTIVE:</span> <span className="text-focus-ring">{primarySelectedPart || 'NONE'}</span></div>
          </div>

          {primarySelectedPart && (
            <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
              <span className="text-white/40 text-[8px] mb-1">KINETIC_MODE</span>
              <div className="flex gap-4 justify-between w-full">
                <span>STATE:</span> 
                <span className={`text-[9px] font-bold ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`}>
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </span>
              </div>
            </div>
          )}

          <div className="border-t border-white/10 pt-2 mt-2 flex flex-col gap-1 w-full text-right">
            <span className="text-white/40 text-[8px] mb-1">RENDER_MODE</span>
            <div className="flex gap-4 justify-between w-full"><span>MODE:</span> <span className="text-focus-ring">{renderMode.toUpperCase()}</span></div>
          </div>
        </DraggablePanel>

        {/* COMMAND LOG (New Draggable Panel) */}
        <DraggablePanel
          id="command-log-panel"
          title="COMMAND_LOG"
          x={panelRects['command-log-panel'].x}
          y={panelRects['command-log-panel'].y}
          minimized={panelRects['command-log-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for command-log: directly below system-status, no gap
            const systemStatusRect = panelRects['system-status-panel'];
            const newY = systemStatusRect.y + systemStatusRect.height; 
            if (panelRects['command-log-panel'].y !== newY) {
              updatePanelPosition('command-log-panel', systemStatusRect.x, newY, panelRects['command-log-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['command-log-panel']}
          className="w-56"
        >
           <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest">
            <span className="text-white/30 mb-1 border-b border-white/10 pb-1">COMMAND_UNIT</span>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[V]</span> <span>Optics</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[P]</span> <span>Pin</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[R]</span> <span>Render Mode</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Z]</span> <span>Undo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Y]</span> <span>Redo</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DRAG</span> <span>Posing</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DBL-CLK</span> <span>Kinetic Mode</span></div>
            <div className="mt-2 text-white/30 border-b border-white/10 pb-1">KINETIC_LEGEND</div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.PURPLE_STRETCH}}></span> <span className="text-accent-purple">STRETCH</span></div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.GREEN_CURL}}></span> <span className="text-accent-green">CURL</span></div>
          </div>
        </DraggablePanel>

        {/* POSE DATA TERMINAL (New Draggable Panel) */}
        <DraggablePanel
          id="pose-data-terminal-panel"
          title="POSE_DATA_TERMINAL"
          x={panelRects['pose-data-terminal-panel'].x}
          y={panelRects['pose-data-terminal-panel'].y}
          minimized={panelRects['pose-data-terminal-panel'].minimized}
          onUpdateRect={(id, rect) => {
            updatePanelRect(id, rect);
            // Dynamic positioning for pose-data-terminal: directly below command-log, no gap
            const commandLogRect = panelRects['command-log-panel'];
            const newY = commandLogRect.y + commandLogRect.height; 
            if (panelRects['pose-data-terminal-panel'].y !== newY) {
              updatePanelPosition('pose-data-terminal-panel', commandLogRect.x, newY, panelRects['pose-data-terminal-panel'].minimized);
            }
          }}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['pose-data-terminal-panel']}
          className="w-56"
        >
          <div className="text-white/70 text-[8px] whitespace-pre-wrap break-all h-full overflow-y-auto custom-scrollbar">
            {poseToString(activePose)}
          </div>
        </DraggablePanel>

        {/* This div wraps the entire mannequin rendering area, no specific z-index here */}
        <div className="w-full h-full bg-selection-super-light bg-triangle-grid flex items-center justify-center relative">
          <Scanlines />
          {showSplash && (
            <div className="absolute top-[8%] left-0 right-0 z-30 flex items-center justify-center pointer-events-none">
              <h1 className="text-6xl font-archaic text-paper/80 animate-terminal-boot tracking-widest uppercase">BITRUVIUS</h1>
            </div>
          )}

          <svg 
            ref={svgRef} 
            width="100%" 
            height="100%" 
            viewBox={autoViewBox} 
            className="overflow-visible relative z-10" 
          >
            <SystemGuides floorY={FLOOR_HEIGHT} /> 
            <g>
              <Mannequin
                pose={activePose}
                showOverlay={true}
                selectedParts={selectedParts}
                visibility={visibility}
                pin={activePin}
                className="text-black"
                onMouseDownOnPart={handleMouseDownOnPart}
                onDoubleClickOnPart={handleDoubleClickOnPart} // Reintroduced
                onMouseDownOnRoot={(e) => { 
                  e.stopPropagation(); 
                  setIsCraneDragging(true); 
                  // FIX: Corrected 'y' to 'startY' to match the dragStartInfo type.
                  dragStartInfo.current = { startX: e.clientX, startY: e.clientY, startRootX: activePose.root.x, startRootY: activePose.root.y }; 
                }}
                jointModes={jointModes} // Reintroduced
                renderMode={renderMode}
              />
            </g>
          </svg>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Vector2D, JointConstraint, RenderMode, PartName } from '../types';
import { ANATOMY } from '../constants';
import { adjustBrightness } from '../utils/color-utils'; // Import the new utility

export interface BoneProps { // Exported for use in Mannequin.tsx cloneElement
  rotation: number;
  length: number;
  width?: number;
  variant?: 'diamond' | 'waist-teardrop-pointy-up' | 'torso-teardrop-pointy-down' | 'collar-horizontal-oval-shape' | 'deltoid-shape' | 'limb-tapered' | 'head-tall-oval' | 'hand-foot-arrowhead-shape';
  showOverlay?: boolean;
  visible?: boolean;
  offset?: Vector2D;
  className?: string;
  children?: React.ReactNode;
  drawsUpwards?: boolean;
  fillOverride?: string; 
  isSelected?: boolean;
  renderMode?: RenderMode; // 'constraint' and 'darken20Percent' removed
  partCategory?: string; 
  jointConstraintMode?: JointConstraint; // New prop for kinetic modes
}

export const COLORS = {
  ANCHOR_RED: "#F87171", // Anchor dots explicitly red
  SELECTION: "#D1D5DB", // Changed from yellow to a light monochrome shade
  RIDGE: "#333333", // For wireframe stroke - kept dark
  PIN_HIGHLIGHT: "#D1D5DB", // Changed from green to light monochrome for active pin

  // Kinetic Colors - Reintroduced for visual feedback
  GREEN_CURL: adjustBrightness("#A3E635", 0.6),    // Desaturated green for Curl
  PURPLE_STRETCH: adjustBrightness("#8B7EC1", 0.8), // Desaturated purple for Stretch

  // Categorical Colors - all default to a dark monochrome for the doll itself
  LIGHT_MONO_HEAD_HAND_FOOT: "#FFFFFF", // Changed to white as requested for head, hands, and feet
  DARK_MONO_BODY_PARTS: "#000000", // Changed to black as requested
  OLIVE: '#000000', // Changed to black as requested for the collar

  DEFAULT_FILL: "#000000", // Fallback / solid black for silhouette
  BACKLIGHT_OPACITY: 0.25, // New constant for backlight mode opacity
};

// Map part categories to colors - simplified to grayscale for the doll's fill
export const COLORS_BY_CATEGORY: { [category: string]: string } = { // Exported
  head: COLORS.LIGHT_MONO_HEAD_HAND_FOOT,
  hand: COLORS.LIGHT_MONO_HEAD_HAND_FOOT,
  foot: COLORS.LIGHT_MONO_HEAD_HAND_FOOT,

  bicep: COLORS.DARK_MONO_BODY_PARTS,
  forearm: COLORS.DARK_MONO_BODY_PARTS,
  collar: COLORS.OLIVE, // Explicitly using the new OLIVE color for the collar
  torso: COLORS.DARK_MONO_BODY_PARTS,
  waist: COLORS.DARK_MONO_BODY_PARTS,
  thigh: COLORS.DARK_MONO_BODY_PARTS,
  shin: COLORS.DARK_MONO_BODY_PARTS,

  default: COLORS.DEFAULT_FILL,
};

const getPartCategoryColor = (category?: string) => {
  if (category && COLORS_BY_CATEGORY[category]) {
    return COLORS_BY_CATEGORY[category];
  }
  return COLORS.DEFAULT_FILL;
};


export const Bone: React.FC<BoneProps> = ({
  rotation,
  length,
  width = 15,
  variant = 'diamond',
  showOverlay = true,
  visible = true,
  offset = { x: 0, y: 0 },
  className,
  children,
  drawsUpwards = false,
  fillOverride,
  isSelected = false,
  renderMode = 'default', // 'constraint' and 'darken20Percent' removed
  partCategory, 
  jointConstraintMode = 'fk', // Default to 'fk'
}) => {
  const getBonePath = (length: number, width: number, variant: string, drawsUpwards: boolean): string => {
    const effectiveLength = drawsUpwards ? -length : length;
    const halfWidth = width / 2;

    switch (variant) {
      case 'head-tall-oval':
        const hH = ANATOMY.HEAD * 0.75;    
        const bW = ANATOMY.HEAD_WIDTH * 0.3; 
        const tW = ANATOMY.HEAD_WIDTH * 0.6; 
        return `M ${-bW / 2},0 L ${bW / 2},0 C ${bW / 2 + 10},0 ${tW / 2},${-hH * 0.4} ${tW / 2},${-hH} L ${-tW / 2},${-hH} C ${-tW / 2},${-hH * 0.4} ${-bW / 2 - 10},0 ${-bW / 2},0 Z`;

      case 'collar-horizontal-oval-shape':
        const collarVisHeight = ANATOMY.COLLAR;
        const collarBaseWidth = ANATOMY.COLLAR_WIDTH;
        const collarTopWidth = collarBaseWidth * 0.5; 
        return `M ${collarBaseWidth / 2},0 C ${collarBaseWidth * 0.3},${-collarVisHeight * 0.3} ${collarTopWidth * 0.7},${-collarVisHeight * 0.6} ${collarTopWidth / 2},${-collarVisHeight} L ${-collarTopWidth / 2},${-collarVisHeight} C ${-collarTopWidth * 0.7},${-collarVisHeight * 0.6} ${-collarBaseWidth * 0.3},${-collarVisHeight * 0.3} ${-collarBaseWidth / 2},0 Z`;

      case 'waist-teardrop-pointy-up':
        const wHeight = ANATOMY.WAIST;
        const wWidth = ANATOMY.WAIST_WIDTH;
        return `M ${wWidth / 2},0 L ${wWidth * 0.15},${-wHeight} L ${-wWidth * 0.15},${-wHeight} L ${-wWidth / 2},0 Z`;

      case 'torso-teardrop-pointy-down':
        const tHeight = ANATOMY.TORSO;
        const tWidth = ANATOMY.TORSO_WIDTH;
        return `M ${tWidth * 0.3},0 C ${tWidth * 0.3},${-tHeight * 0.3} ${tWidth / 2},${-tHeight * 0.7} ${tWidth / 2},${-tHeight} L ${-tWidth / 2},${-tHeight} C ${-tWidth / 2},${-tHeight * 0.7} ${-tWidth * 0.3},${-tHeight * 0.3} ${-tWidth * 0.3},0 Z`;

      case 'deltoid-shape':
        const dHeight = ANATOMY.UPPER_ARM;
        const shoulderWidth = ANATOMY.LIMB_WIDTH_ARM; 
        return `M ${shoulderWidth / 2} 0
                C ${shoulderWidth / 2} ${dHeight * 0.2} ${shoulderWidth * 1.2 / 2} ${dHeight * 0.4} ${shoulderWidth * 1.2 / 2} ${dHeight * 0.7}
                L 0 ${dHeight}
                L ${-shoulderWidth * 1.2 / 2} ${dHeight * 0.7}
                C ${-shoulderWidth * 1.2 / 2} ${dHeight * 0.4} ${-shoulderWidth / 2} ${dHeight * 0.2} ${-shoulderWidth / 2} 0 Z`;

      case 'limb-tapered':
        const endWidth = width * 0.65;
        return `M ${width / 2},0 L ${endWidth / 2},${effectiveLength} L ${-endWidth / 2},${effectiveLength} L ${-width / 2},0 Z`;

      case 'hand-foot-arrowhead-shape':
        const hBaseWidth = width * 0.4; 
        const hMaxWidth = width;
        const flareY = effectiveLength * 0.2; 
        return `M ${-hBaseWidth / 2},0 L ${hBaseWidth / 2},0 L ${hMaxWidth / 2},${flareY} L 0,${effectiveLength} L ${-hMaxWidth / 2},${flareY} Z`;

      default:
        const split = effectiveLength * 0.4;
        return `M 0 0 L ${halfWidth} ${split} L 0 ${effectiveLength} L ${-halfWidth} ${split} Z`;
    }
  };

  const partCategoryColor = getPartCategoryColor(partCategory);

  const pathFill = useMemo(() => {
    if (renderMode === 'wireframe') return 'none';
    if (renderMode === 'silhouette') return COLORS.DEFAULT_FILL; // Solid black fill for silhouette
    if (renderMode === 'backlight') return COLORS.DEFAULT_FILL; // Black fill for backlight mode

    // Default mode: use categorical color, which is now monochrome.
    return fillOverride || partCategoryColor;
  }, [renderMode, fillOverride, partCategoryColor]);

  const pathOpacity = useMemo(() => {
    if (renderMode === 'backlight') return COLORS.BACKLIGHT_OPACITY;
    return 1; // Default to opaque
  }, [renderMode]);

  const pathStroke = useMemo(() => {
    if (isSelected) return COLORS.SELECTION; // Selection always has priority for stroke color

    if (renderMode === 'wireframe') return COLORS.RIDGE;
    if (renderMode === 'backlight') return COLORS.RIDGE; // Outline for backlight mode

    // In silhouette mode, no stroke unless selected
    if (renderMode === 'silhouette') {
      return 'none';
    }

    return 'none'; // Default behavior for 'default' mode (no stroke by default)
  }, [isSelected, renderMode]);

  const pathStrokeWidth = useMemo(() => {
    if (isSelected) return 3; // Selected parts get a thicker stroke

    if (renderMode === 'wireframe' || renderMode === 'backlight') return 0.5; // Thinner stroke for wireframe and backlight

    // In silhouette mode, no stroke width unless selected
    if (renderMode === 'silhouette') {
      return 0;
    }

    return 0; // Default behavior for 'default' mode (no stroke width by default)
  }, [isSelected, renderMode]);

  const overlayLineStroke = useMemo(() => {
    if (renderMode === 'default' && showOverlay) {
      if (jointConstraintMode === 'stretch') return COLORS.PURPLE_STRETCH;
      if (jointConstraintMode === 'curl') return COLORS.GREEN_CURL;
    }
    // For backlight, use a distinct color for the axis lines to stand out
    if (renderMode === 'backlight') return COLORS.SELECTION;
    return COLORS.RIDGE; // Default for FK or other modes
  }, [renderMode, showOverlay, jointConstraintMode]);


  const visualEndPoint = drawsUpwards ? -length : length;
  const transform = (offset.x !== 0 || offset.y !== 0)
    ? `translate(${offset.x}, ${offset.y}) rotate(${rotation})`
    : `rotate(${rotation})`;

  return (
    <g transform={transform} className={className}>
      {visible && (
        <React.Fragment>
          <path
            d={getBonePath(length, width, variant, drawsUpwards)}
            fill={pathFill}
            stroke={pathStroke}
            strokeWidth={pathStrokeWidth}
            paintOrder="stroke"
            opacity={pathOpacity}
          />
          {/* Overlay line for axis, only in default mode, now with kinetic color */}
          {showOverlay && renderMode !== 'wireframe' && ( // Show overlay in default, backlight, silhouette, but not wireframe
            <line x1="0" y1="0" x2="0" y2={visualEndPoint} stroke={overlayLineStroke} strokeWidth={1} opacity={0.5} strokeLinecap="round" />
          )}
        </React.Fragment>
      )}

      <g transform={`translate(0, ${visualEndPoint})`}>{children}</g>

      {/* Anchor (red dot) at the start of the bone, always visible if showOverlay */}
      {showOverlay && visible && (
        <circle 
          cx="0" cy="0" r={isSelected ? 7 : 5} 
          fill={COLORS.ANCHOR_RED} 
          className="pointer-events-none drop-shadow-md transition-all duration-150" 
          data-no-export={true} 
        />
      )}
    </g>
  );
};

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import { Pose, PartName, PartSelection, PartVisibility, AnchorName, partNameToPoseKey, JointConstraint, RenderMode, Vector2D, ViewMode } from './types';
import { RESET_POSE, FLOOR_HEIGHT, JOINT_LIMITS, ANATOMY, GROUND_STRIP_HEIGHT } from './constants'; 
import { getJointPositions, getShortestAngleDiffDeg } from './utils/kinematics';
import { Scanlines, SystemGuides } from './components/SystemGrid';
import { Mannequin, getPartCategory, getPartCategoryDisplayName } from './components/Mannequin'; 
import { DraggablePanel } from './components/DraggablePanel';
import { COLORS_BY_CATEGORY, COLORS } from './components/Bone';
import { poseToString } from './utils/pose-parser';
import { RotationWheelControl } from './components/RotationWheelControl';

interface PanelRect {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  minimized: boolean;
}

const App: React.FC = () => {
  const [activePose, setActivePose] = useState<Pose>(RESET_POSE);
  const undoStack = useRef<Pose[]>([]);
  const redoStack = useRef<Pose[]>([]); 
  redoStack.current = []; // Clear redo stack on mount


  const [viewMode, setViewMode] = useState<ViewMode>('default');
  const [activePin, setActivePin] = useState<AnchorName>(PartName.Waist); // Default to Waist
  const [renderMode, setRenderMode] = useState<RenderMode>('default');

  const [selectedParts, setSelectedParts] = useState<PartSelection>(() => {
    const initialSelection: PartSelection = Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: false }), {} as PartSelection);
    initialSelection[PartName.Waist] = true; 
    return initialSelection;
  });

  const [visibility] = useState<PartVisibility>(() => Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: true }), {} as PartVisibility));

  const [jointModes, setJointModes] = useState<Record<PartName, JointConstraint>>(() => 
    Object.values(PartName).reduce((acc, name) => ({ ...acc, [name]: 'fk' }), {} as Record<PartName, JointConstraint>)
  );

  const [isAdjusting, setIsAdjusting] = useState(false);
  const [rotatingPart, setRotatingPart] = useState<PartName | null>(null);
  const rotationStartInfo = useRef<{ 
    startAngle: number; 
    startRotationValue: number; 
    pointerX: number; 
    pointerY: number;
    initialPinnedPos: Vector2D | null;
  } | null>(null);

  const [isEffectorDragging, setIsEffectorDragging] = useState(false);
  const [effectorPart, setEffectorPart] = useState<PartName | null>(null);

  const svgRef = useRef<SVGSVGElement>(null); 
  const [isCraneActive] = useState(false);
  const [isCraneDragging, setIsCraneDragging] = useState(false);
  const dragStartInfo = useRef<{ startX: number; startY: number; startRootX: number; startRootY: number } | null>(dragStartInfoInitial());

  function dragStartInfoInitial() {
    return { startX: 0, startY: 0, startRootX: 0, startRootY: 0 };
  }

  const [showSplash, setShowSplash] = useState(true);
  const [isAirMode] = useState(false);

  const [windowSize, setWindowSize] = useState({
    innerWidth: window.innerWidth,
    innerHeight: window.innerHeight,
  });

  // Panel Z-index management for the single settings panel
  const [panelZIndices, setPanelZIndices] = useState<Record<string, number>>({
    'model-settings-panel': 102,
  });
  const nextZIndex = useRef<number>(103);

  const bringPanelToFront = useCallback((id: string) => {
    setPanelZIndices(prev => {
      const newZIndices = { ...prev };
      newZIndices[id] = nextZIndex.current++;
      return newZIndices;
    });
  }, []);

  // --- Panel Position/Size Management for the single settings panel ---
  const [panelRects, setPanelRects] = useState<Record<string, PanelRect>>({
    'model-settings-panel': { id: 'model-settings-panel', x: window.innerWidth - 224 - 16, y: 16, width: 224, height: 700, minimized: true },
  });

  const updatePanelRect = useCallback((id: string, newRect: Omit<PanelRect, 'x' | 'y'>) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.width !== newRect.width || existingRect.height !== newRect.height || existingRect.minimized !== newRect.minimized) {
        return { ...prev, [id]: { ...existingRect, ...newRect } };
      }
      return prev;
    });
  }, []);

  const updatePanelPosition = useCallback((id: string, newX: number, newY: number, minimized: boolean) => {
    setPanelRects(prev => {
      const existingRect = prev[id];
      if (!existingRect || existingRect.x !== newX || existingRect.y !== newY || existingRect.minimized !== minimized) {
        return { ...prev, [id]: { ...existingRect, x: newX, y: newY, minimized: minimized } };
      }
      return prev;
    });
  }, []);
  // --- End Panel Position/Size Management ---

  const primarySelectedPart = useMemo(() => {
    return (Object.entries(selectedParts).find(([p, sel]) => sel)?.[0]) as PartName | undefined;
  }, [selectedParts]);

  // Dynamically calculate viewBox based on viewMode and windowSize
  const autoViewBox = useMemo(() => {
    const configs = {
      zoomed: { x: -900, y: 1950, w: 1800, h: 1550 },
      default: { x: -1112.5, y: 1287.5, w: 2225, h: 2212.5 },
      lotte: { x: -1325, y: 625, w: 2650, h: 2875 },
      wide: { x: -1750, y: -700, w: 3500, h: 4200 },
    };

    if (viewMode === 'mobile') {
      const screenAspectRatio = windowSize.innerWidth / windowSize.innerHeight;

      const mannequinIntrinsicHeight = (
        ANATOMY.HEAD +
        ANATOMY.HEAD_NECK_GAP_OFFSET +
        ANATOMY.COLLAR +
        ANATOMY.TORSO +
        ANATOMY.WAIST +
        ANATOMY.LEG_UPPER +
        ANATOMY.LEG_LOWER +
        ANATOMY.FOOT
      );

      const verticalPaddingRatio = 0.20;
      const contentHeightInSVGUnits = mannequinIntrinsicHeight * (1 + verticalPaddingRatio);

      const viewBoxHeight = contentHeightInSVGUnits;
      const viewBoxWidth = viewBoxHeight * screenAspectRatio;

      const groundPlaneBuffer = GROUND_STRIP_HEIGHT * 1.5;
      const desiredViewBoxBottom = FLOOR_HEIGHT + groundPlaneBuffer;
      const viewBoxY = desiredViewBoxBottom - viewBoxHeight;
      const viewBoxX = -viewBoxWidth / 2;

      return `${viewBoxX} ${viewBoxY} ${viewBoxWidth} ${viewBoxHeight}`;

    } else {
      const c = configs[viewMode];
      return `${c.x} ${c.y} ${c.w} ${c.h}`;
    }
  }, [viewMode, windowSize.innerWidth, windowSize.innerHeight]);

  // --- Physics Validation Logic ---
  const isValidMove = useCallback((
    potentialPose: Pose,
    originalPose: Pose,
    activePin: AnchorName,
    initialPinnedPos: Vector2D | null,
    isCraneDragging: boolean,
    isEffectorDragging: boolean,
    partBeingRotated: PartName | null,
    isAirMode: boolean,
  ): boolean => {
    if (isAirMode) return true;

    const potentialJoints = getJointPositions(potentialPose, activePin);
    const originalJoints = getJointPositions(originalPose, activePin);

    // 1. Check Pin Immovability
    if (!isCraneDragging && initialPinnedPos && activePin) {
        const currentPinnedPosInPotentialPose = potentialJoints[activePin as keyof typeof potentialJoints];
        if (currentPinnedPosInPotentialPose) {
            const dx = currentPinnedPosInPotentialPose.x - initialPinnedPos.x;
            const dy = currentPinnedPosInPotentialPose.y - initialPinnedPos.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            const PIN_TOLERANCE = 2;
            if (distance > PIN_TOLERANCE) {
                return false;
            }
        }
    }

    // 2. Check Ground Collision
    const isFootRelatedPart = (part: PartName | null) =>
      part === PartName.LAnkle || part === PartName.RAnkle || part === PartName.LSkin || part === PartName.RSkin; 

    const relevantToGrounding = isCraneDragging || isEffectorDragging || isFootRelatedPart(partBeingRotated);

    if (relevantToGrounding) {
      const lFootTipY = potentialJoints.lFootTip?.y || -Infinity;
      const rFootTipY = potentialJoints.rFootTip?.y || -Infinity;
      const lowestFootTipY = Math.max(lFootTipY, rFootTipY);

      const GROUND_COLLISION_THRESHOLD = 2;
      if (lowestFootTipY > FLOOR_HEIGHT + GROUND_COLLISION_THRESHOLD) {
          return false;
      }
    }

    return true;
  }, [activePin, isAirMode, isCraneDragging]); 

  const validateAndApplyPoseUpdate = useCallback((
      proposedUpdates: Partial<Pose>,
      partBeingDirectlyManipulated: PartName | null,
      isEffectorDrag: boolean,
  ) => {
      setActivePose(prev => {
          let tentativeNextPose: Pose = { ...prev, ...proposedUpdates };

          if (!isValidMove(
              tentativeNextPose,
              prev,
              activePin,
              rotationStartInfo.current?.initialPinnedPos || null,
              isCraneDragging, 
              isEffectorDrag,
              partBeingDirectlyManipulated,
              isAirMode,
          )) {
              return prev;
          }

          undoStack.current.push(prev);
          redoStack.current.length = 0;
          return tentativeNextPose;
      });
  }, [activePin, isAirMode, isCraneDragging, isValidMove]);

  const handleUndo = useCallback(() => {
    if (undoStack.current.length > 0) {
      setActivePose(prev => {
        redoStack.current.push(prev); 
        const nextPose = undoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleRedo = useCallback(() => {
    if (redoStack.current.length > 0) {
      setActivePose(prev => {
        undoStack.current.push(prev);
        const nextPose = redoStack.current.pop()!;
        return nextPose;
      });
    }
  }, []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!svgRef.current) return;
    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    if (isCraneDragging && dragStartInfo.current) {
      const dx = transformedPoint.x - dragStartInfo.current.startX;
      const dy = transformedPoint.y - dragStartInfo.current.startY;

      const newRootX = dragStartInfo.current.startRootX + dx;
      const newRootY = dragStartInfo.current.startRootY + dy;

      validateAndApplyPoseUpdate({ root: { x: newRootX, y: newRootY } }, null, false);

    } else if (isAdjusting && rotatingPart && rotationStartInfo.current) {
      const joints = getJointPositions(activePose, activePin);
      const pivot = joints[rotatingPart]; 
      if (!pivot) return;

      const currentAngleDeg = Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI;
      const startAngleDeg = rotationStartInfo.current.startAngle; 

      const angleDeltaDeg = getShortestAngleDiffDeg(currentAngleDeg, startAngleDeg);

      let newRotationValue = rotationStartInfo.current.startRotationValue + angleDeltaDeg;
      const partKey = partNameToPoseKey[rotatingPart];
      const limits = JOINT_LIMITS[partKey];

      if (limits) {
        newRotationValue = Math.max(limits.min, Math.min(limits.max, newRotationValue));
      }

      validateAndApplyPoseUpdate({ [partKey]: newRotationValue }, rotatingPart, false);

    } 
  }, [isAdjusting, rotatingPart, isCraneDragging, activePose, validateAndApplyPoseUpdate, activePin]);

  const handleMouseUp = useCallback(() => {
    setIsAdjusting(false);
    setRotatingPart(null);
    setIsCraneDragging(false);
    setEffectorPart(null); 
    setIsEffectorDragging(false); 
    rotationStartInfo.current = null;
    dragStartInfo.current = dragStartInfoInitial(); 
  }, []);

  const getInitialPinnedPos = useCallback(() => {
    const joints = getJointPositions(activePose, activePin);
    let initialPinnedPos: Vector2D | null = null;

    if (activePin === 'root') {
      initialPinnedPos = joints.root;
    } else if (activePin === 'lFootTip') {
      initialPinnedPos = joints.lFootTip;
    } else if (activePin === 'rFootTip') {
      initialPinnedPos = joints.rFootTip;
    } else {
      initialPinnedPos = joints[activePin];
    }

    if (initialPinnedPos && (activePin === 'lFootTip' || activePin === 'rFootTip')) {
      initialPinnedPos = { ...initialPinnedPos, y: Math.min(initialPinnedPos.y, FLOOR_HEIGHT) };
    }
    return initialPinnedPos;
  }, [activePose, activePin]);

  const handleDoubleClickOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    setJointModes(prev => {
      const currentMode = prev[part];
      let nextMode: JointConstraint;
      if (currentMode === 'fk') {
        nextMode = 'stretch';
      } else if (currentMode === 'stretch') {
        nextMode = 'curl';
      } else if (currentMode === 'curl') {
        nextMode = 'stretch';
      } else {
        nextMode = 'fk';
      }
      return { ...prev, [part]: nextMode };
    });
  }, []);

  const handleMouseDownOnPart = useCallback((part: PartName, e: React.MouseEvent<SVGGElement>) => {
    e.stopPropagation();
    if (!svgRef.current) return;

    setSelectedParts(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(k => next[k as PartName] = k === part);
      return next;
    });

    const joints = getJointPositions(activePose, activePin);
    const pivot = joints[part]; 
    if (!pivot) return;

    const svgPoint = svgRef.current.createSVGPoint();
    svgPoint.x = e.clientX; svgPoint.y = e.clientY;
    const ctm = svgRef.current.getScreenCTM();
    if (!ctm) return;
    const transformedPoint = svgPoint.matrixTransform(ctm.inverse());

    setIsAdjusting(true);
    setRotatingPart(part);
    rotationStartInfo.current = {
      startAngle: Math.atan2(transformedPoint.y - pivot.y, transformedPoint.x - pivot.x) * 180 / Math.PI,
      startRotationValue: (activePose as any)[partNameToPoseKey[part]] || 0,
      pointerX: transformedPoint.x, pointerY: transformedPoint.y, initialPinnedPos: getInitialPinnedPos()
    };
  }, [activePose, activePin, getInitialPinnedPos]);

  const cycleRenderMode = useCallback(() => {
    setRenderMode(prev => {
      if (prev === 'default') return 'wireframe';
      if (prev === 'wireframe') return 'silhouette';
      if (prev === 'silhouette') return 'backlight';
      if (prev === 'backlight') return 'default';
      return 'default';
    });
  }, []);

  const cycleViewMode = useCallback(() => {
    setViewMode(prev => {
      if (prev === 'default') return 'lotte';
      if (prev === 'lotte') return 'wide';
      if (prev === 'wide') return 'mobile';
      if (prev === 'mobile') return 'zoomed';
      if (prev === 'zoomed') return 'default';
      return 'default';
    });
  }, []);

  // Handler for toggling the minimized state of the settings panel
  const toggleSettingsPanelMinimized = useCallback(() => {
    setPanelRects(prev => {
      const currentPanel = prev['model-settings-panel'];
      return {
        ...prev,
        'model-settings-panel': { ...currentPanel, minimized: !currentPanel.minimized }
      };
    });
    bringPanelToFront('model-settings-panel'); // Bring to front when toggled
  }, [bringPanelToFront]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'v') cycleViewMode();
      if (e.key === 'p') setActivePin(prev => {
        if (prev === PartName.Waist) return PartName.LAnkle;
        if (prev === PartName.LAnkle) return 'lFootTip'; 
        if (prev === 'lFootTip') return PartName.RAnkle;
        if (prev === PartName.RAnkle) return 'rFootTip';
        if (prev === 'rFootTip') return 'root';
        return PartName.Waist;
      });
      if (e.key === 'r') cycleRenderMode();
      if (e.key === 'z' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        handleUndo();
      }
      if (e.key === 'y' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        handleRedo();
      }
    };

    const handleResize = () => {
      setWindowSize({
        innerWidth: window.innerWidth,
        innerHeight: window.innerHeight,
      });
      // Adjust panel position on resize if it would go off-screen
      setPanelRects(prev => {
        const panel = prev['model-settings-panel'];
        const newX = Math.min(panel.x, window.innerWidth - panel.width - 16);
        const newY = Math.min(panel.y, window.innerHeight - (panel.minimized ? 40 : panel.height) - 16); // 40px is rough minimized height
        return { ...prev, 'model-settings-panel': { ...panel, x: Math.max(0, newX), y: Math.max(0, newY) } };
      });
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('resize', handleResize);
    const timer = setTimeout(() => setShowSplash(false), 2000);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('resize', handleResize);
      clearTimeout(timer);
    };
  }, [handleMouseMove, handleMouseUp, handleUndo, handleRedo, cycleRenderMode, cycleViewMode]);

  const getPinName = (pin: AnchorName) => {
    if (pin === PartName.Waist) return 'HIPS (Default Anchor)';
    if (pin === PartName.LAnkle) return 'LEFT ANKLE';
    if (pin === 'lFootTip') return 'LEFT FOOT TIP';
    if (pin === PartName.RAnkle) return 'RIGHT ANKLE';
    if (pin === 'rFootTip') return 'RIGHT FOOT TIP';
    if (pin === 'root') return 'GLOBAL ROOT';
    return 'UNKNOWN';
  };

  const getKineticModeDisplayName = (mode: JointConstraint) => {
    switch (mode) {
      case 'fk': return 'STANDARD (No Effects)';
      case 'stretch': return 'STRETCH (PULLS PARENT)';
      case 'curl': return 'CURL (PULLS CHILD)';
      default: return 'UNKNOWN';
    }
  };

  const getKineticModeDisplayColorClass = (mode: JointConstraint) => {
    switch (mode) {
      case 'stretch': return 'text-accent-purple';
      case 'curl': return 'text-accent-green';
      case 'fk': return 'text-focus-ring';
      default: return 'text-white/70';
    }
  };

  const getRenderModeDisplayName = (mode: RenderMode) => {
    switch (mode) {
      case 'default': return 'STANDARD (Solid)';
      case 'wireframe': return 'WIREFRAME (Outline)';
      case 'silhouette': return 'MONOCHROME (Black Fill)';
      case 'backlight': return 'X-RAY (Transparent)';
      default: return 'UNKNOWN';
    }
  };


  const handlePartRotationWheelChange = useCallback((newValue: number) => {
    if (!primarySelectedPart) return;
    const partKey = partNameToPoseKey[primarySelectedPart];

    validateAndApplyPoseUpdate({ [partKey]: newValue }, primarySelectedPart, false);
  }, [primarySelectedPart, validateAndApplyPoseUpdate]);

  const handleBodyRotationWheelChange = useCallback((newValue: number) => {
    validateAndApplyPoseUpdate({ bodyRotation: newValue }, null, false);
  }, [validateAndApplyPoseUpdate]);

  const allPanelRectsArray = useMemo(() => Object.values(panelRects), [panelRects]);
  const settingsPanel = panelRects['model-settings-panel'];

  return (
    <div className="w-full h-full bg-mono-darker shadow-2xl flex flex-col relative touch-none fixed inset-0 z-50 overflow-hidden text-ink font-mono">
      <div className="relative flex h-full w-full">
        {/* Settings Toggle Button (Gear Icon) */}
        <button
          onClick={toggleSettingsPanelMinimized}
          className="absolute top-4 right-4 z-[1000] p-2 bg-black/50 hover:bg-black/70 rounded-full border border-white/20 text-ink hover:text-mono-light transition-colors duration-200"
          aria-label={settingsPanel.minimized ? "Open Model Settings" : "Close Model Settings"}
        >
          <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
            <path d="M17.243 14.757l-.37-.37c-.63.63-1.39 1.05-2.22 1.25l-.23.95a.996.996 0 01-1.22.75l-2-.5a.996.996 0 01-.75-1.22l.23-.95c-.83-.2-1.59-.62-2.22-1.25l-.37.37a.997.997 0 01-1.41 0l-.707-.707a.997.997 0 010-1.414l.37-.37c-.63-.63-1.05-1.39-1.25-2.22l-.95-.23a.996.996 0 01-.75-1.22l.5-2a.996.996 0 011.22-.75l.95.23c.2-.83.62-1.59 1.25-2.22l-.37-.37a.997.997 0 010-1.414l.707-.707a.997.997 0 011.414 0l.37.37c.63-.63 1.39-1.05 2.22-1.25l.23-.95a.996.996 0 011.22-.75l2 .5a.996.996 0 01.75 1.22l-.23.95c.83.2 1.59.62 2.22 1.25l.37-.37a.997.997 0 011.414 0l.707.707a.997.997 0 010 1.414l-.37.37c.63.63 1.05 1.39 1.25 2.22l.95.23a.996.996 0 01.75 1.22l-.5 2a.996.996 0 01-1.22.75l-.95-.23c-.2.83-.62 1.59-1.25 2.22l.37.37a.997.997 0 010 1.414l-.707.707a.997.997 0 01-1.414 0zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" fillRule="evenodd"></path>
          </svg>
        </button>

        {/* MODEL SETTINGS (New Master Draggable Panel) */}
        <DraggablePanel
          id="model-settings-panel"
          title="MODEL SETTINGS"
          x={settingsPanel.x}
          y={settingsPanel.y}
          minimized={settingsPanel.minimized}
          onUpdateRect={(id, rect) => updatePanelRect(id, rect)}
          onUpdatePosition={(id, x, y, minimized) => updatePanelPosition(id, x, y, minimized)}
          allPanelRects={allPanelRectsArray}
          onBringToFront={bringPanelToFront}
          currentZIndex={panelZIndices['model-settings-panel']}
          className="w-56 max-h-[90vh] overflow-y-auto custom-scrollbar" // Allow scrolling if content is too long
        >
          {/* Section: Joint Control */}
          <div className="flex flex-col gap-1 w-full text-left border-b border-white/10 pb-3 mb-3">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide">JOINT CONTROL</h3>
            <div className="bg-white/5 p-2 rounded border border-white/10 flex flex-col gap-2">
              <div className="flex items-center gap-2">
                <span className="w-3 h-3 rounded-full" style={{ backgroundColor: primarySelectedPart ? COLORS_BY_CATEGORY[getPartCategory(primarySelectedPart)] : '#9CA3AF' }}></span>
                <span className="text-white/70 text-[9px] uppercase font-bold">
                  {primarySelectedPart ? getPartCategoryDisplayName(primarySelectedPart) : 'NO JOINT SELECTED'}
                </span>
                {primarySelectedPart && <span className="text-accent-red animate-pulse text-[8px]">ACTIVE</span>}
              </div>
              <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
                <span className="text-white/40 uppercase text-[8px]">Joint_Rotation_Angle</span>
                <RotationWheelControl
                  value={primarySelectedPart ? activePose[partNameToPoseKey[primarySelectedPart]] || 0 : 0}
                  min={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.min || -180 : -180}
                  max={primarySelectedPart ? JOINT_LIMITS[partNameToPoseKey[primarySelectedPart]]?.max || 180 : 180}
                  step={5}
                  onChange={handlePartRotationWheelChange}
                  isDisabled={!primarySelectedPart}
                  className="my-2"
                />
              </div>
              {primarySelectedPart && (
                <div className="flex flex-col gap-1 border-t border-white/10 pt-2 items-center">
                  <span className="text-white/40 uppercase text-[8px]">Joint_Behavior_Mode</span>
                  <button
                    onClick={() => {
                      if (primarySelectedPart) {
                        setJointModes(prev => {
                          const currentMode = prev[primarySelectedPart];
                          let nextMode: JointConstraint;
                          if (currentMode === 'fk') {
                            nextMode = 'stretch';
                          } else if (currentMode === 'stretch') {
                            nextMode = 'curl';
                          } else if (currentMode === 'curl') {
                            nextMode = 'stretch';
                          } else {
                            nextMode = 'fk';
                          }
                          return { ...prev, [primarySelectedPart]: nextMode };
                        });
                      }
                    }}
                    disabled={!primarySelectedPart}
                    className={`w-full text-[9px] font-bold text-center px-2 py-1 transition-all border ${
                      !primarySelectedPart
                        ? 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                        : `bg-white/10 border-white/20 hover:bg-white/20 ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`
                    }`}
                    aria-label={`Toggle Kinetic Mode for ${getPartCategoryDisplayName(primarySelectedPart)}. Current mode: ${getKineticModeDisplayName(jointModes[primarySelectedPart])}`}
                    aria-pressed={jointModes[primarySelectedPart] !== 'fk'}
                  >
                    {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                  </button>
                </div>
              )}
            </div>
            {/* Undo/Redo Buttons */}
            <div className="border-t border-white/10 pt-2 mt-4 w-full flex justify-between gap-2">
              <button
                onClick={handleUndo}
                disabled={undoStack.current.length === 0}
                className={`flex-1 text-[9px] px-2 py-1 border ${
                  undoStack.current.length > 0 
                  ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/20' 
                  : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                } transition-all`}
                aria-label="Undo last action"
              >
                UNDO
              </button>
              <button
                onClick={handleRedo}
                disabled={redoStack.current.length === 0}
                className={`flex-1 text-[9px] px-2 py-1 border ${
                  redoStack.current.length > 0 
                  ? 'bg-white/10 border-white/20 text-white/70 hover:bg-white/10' 
                  : 'bg-white/5 border-transparent text-white/30 cursor-not-allowed'
                } transition-all`}
                aria-label="Redo last action"
              >
                REDO
              </button>
            </div>
          </div>

          {/* Section: Fixed Point (Pin) Options */}
          <div className="flex flex-col gap-1 w-full text-left border-b border-white/10 pb-3 mb-3">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide">FIXED POINT (PIN) OPTIONS</h3>
            <span className="text-white/40 text-[8px] uppercase">Select_Pin_Location</span>
            <div className="grid grid-cols-2 gap-1">
              {([PartName.Waist, PartName.LAnkle, 'lFootTip', PartName.RAnkle, 'rFootTip', 'root'] as AnchorName[]).map(pinOption => (
                <button
                  key={pinOption}
                  onClick={() => setActivePin(pinOption)}
                  className={`text-[9px] text-left px-2 py-1 transition-all border ${
                    activePin === pinOption
                    ? 'bg-accent-red/30 border-accent-red text-accent-red'
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={activePin === pinOption}
                  aria-label={`Set fixed point to ${getPinName(pinOption)}`}
                >
                  {getPinName(pinOption)}
                </button>
              ))}
            </div>
            <div className="flex flex-col gap-1 border-t border-white/10 pt-2 mt-4 items-center">
              <span className="text-white/40 uppercase text-[8px]">Global_Rotation_Angle</span>
              <RotationWheelControl
                value={activePose.bodyRotation || 0}
                min={-180}
                max={180}
                step={5}
                onChange={handleBodyRotationWheelChange}
                isDisabled={false}
                className="my-2"
              />
            </div>
          </div>

          {/* Section: Display Modes */}
          <div className="flex flex-col gap-1 w-full text-left border-b border-white/10 pb-3 mb-3">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide">DISPLAY MODES</h3>
            <span className="text-white/40 text-[8px] uppercase">Render_Style</span>
            <div className="flex flex-col gap-1">
              {(['default', 'wireframe', 'silhouette', 'backlight'] as RenderMode[]).map(mode => (
                <button
                  key={mode}
                  onClick={() => setRenderMode(mode)}
                  className={`text-[9px] text-center px-2 py-1 transition-all border ${
                    renderMode === mode 
                    ? 'bg-selection/30 border-selection text-selection' 
                    : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={renderMode === mode}
                  aria-label={`Set display mode to ${getRenderModeDisplayName(mode)}`}
                >
                  {getRenderModeDisplayName(mode).toUpperCase()}
                </button>
              ))}
            </div>
            <span className="text-white/40 text-[8px] uppercase mt-4">Viewport_Zoom</span>
            <div className="grid grid-cols-2 gap-1 items-center">
              {(['default', 'lotte', 'wide', 'mobile', 'zoomed'] as ViewMode[]).map(_mode => (
                <button
                  key={_mode}
                  onClick={() => setViewMode(_mode)}
                  className={`col-span-1 text-[9px] text-center px-1 py-0.5 transition-all border ${
                    viewMode === _mode
                      ? 'bg-accent-green/30 border-accent-green text-accent-green'
                      : 'bg-white/5 border-transparent text-white/50 hover:bg-white/10'
                  }`}
                  aria-pressed={viewMode === _mode}
                  aria-label={`Set viewport zoom to ${_mode.toUpperCase()}`}
                >
                  {_mode.toUpperCase()}
                </button>
              ))}
            </div>
          </div>

          {/* Section: System Monitor */}
          <div className="flex flex-col gap-1 w-full text-right border-b border-white/10 pb-3 mb-3">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide text-left">SYSTEM MONITOR</h3>
            <div className="flex gap-4 justify-between w-full"><span>VIEWPORT:</span> <span className="text-accent-green text-right">{viewMode.toUpperCase()}</span></div>
            <div className="flex gap-4 justify-between w-full"><span>FIXED POINT:</span> <span className="text-accent-red">{getPinName(activePin)}</span></div>
            <div className="flex gap-4 justify-between w-full"><span>ACTIVE JOINT:</span> <span className="text-focus-ring">{primarySelectedPart ? getPartCategoryDisplayName(primarySelectedPart) : 'NONE'}</span></div>
            {primarySelectedPart && (
              <div className="flex gap-4 justify-between w-full">
                <span>JOINT BEHAVIOR:</span> 
                <span className={`text-[9px] font-bold ${getKineticModeDisplayColorClass(jointModes[primarySelectedPart])}`}>
                  {getKineticModeDisplayName(jointModes[primarySelectedPart])}
                </span>
              </div>
            )}
            <div className="flex gap-4 justify-between w-full"><span>DISPLAY MODE:</span> <span className="text-focus-ring">{getRenderModeDisplayName(renderMode).toUpperCase()}</span></div>
          </div>

          {/* Section: Hotkey Commands */}
          <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest border-b border-white/10 pb-3 mb-3">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide">HOTKEY COMMANDS</h3>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[V]</span> <span>TOGGLE ZOOM</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[P]</span> <span>CYCLE FIXED POINT</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[R]</span> <span>CYCLE DISPLAY MODE</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Z]</span> <span>UNDO LAST ACTION</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">[CTRL/CMD+Y]</span> <span>REDO LAST ACTION</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DRAG</span> <span>POSE JOINT</span></div>
            <div className="flex gap-2 items-center"><span className="text-accent-green">DBL-CLK</span> <span>TOGGLE JOINT BEHAVIOR</span></div>
            <div className="mt-2 text-white/30 border-b border-white/10 pb-1">BEHAVIOR_LEGEND</div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.PURPLE_STRETCH}}></span> <span className="text-accent-purple">STRETCH</span></div>
            <div className="flex gap-2 items-center"><span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS.GREEN_CURL}}></span> <span className="text-accent-green">CURL</span></div>
          </div>

          {/* Section: Pose Data Export */}
          <div className="flex flex-col gap-1 w-full text-left uppercase tracking-widest">
            <h3 className="text-focus-ring mb-2 font-bold uppercase tracking-wide">POSE DATA EXPORT</h3>
            <div className="text-white/70 text-[8px] whitespace-pre-wrap break-all h-40 overflow-y-auto custom-scrollbar bg-white/5 p-2 rounded border border-white/10">
              {poseToString(activePose)}
            </div>
          </div>
        </DraggablePanel>

        <div className="w-full h-full bg-selection-super-light bg-triangle-grid flex items-center justify-center relative">
          <Scanlines />
          {showSplash && (
            <div className="absolute top-[8%] left-0 right-0 z-30 flex items-center justify-center pointer-events-none">
              <h1 className="text-6xl font-archaic text-paper/80 animate-terminal-boot tracking-widest uppercase">BITRUVIUS</h1>
            </div>
          )}

          <svg 
            ref={svgRef} 
            width="100%" 
            height="100%" 
            viewBox={autoViewBox} 
            className="overflow-visible relative z-10" 
          >
            <SystemGuides floorY={FLOOR_HEIGHT} /> 
            <g>
              <Mannequin
                pose={activePose}
                showOverlay={true}
                selectedParts={selectedParts}
                visibility={visibility}
                pin={activePin}
                className="text-black"
                onMouseDownOnPart={handleMouseDownOnPart}
                onDoubleClickOnPart={handleDoubleClickOnPart}
                onMouseDownOnRoot={(e) => { 
                  e.stopPropagation(); 
                  setIsCraneDragging(true); 
                  dragStartInfo.current = { startX: e.clientX, startY: e.clientY, startRootX: activePose.root.x, startRootY: activePose.root.y }; 
                }}
                jointModes={jointModes}
                renderMode={renderMode}
              />
            </g>
          </svg>
        </div>
      </div>
    </div>
  );
};

export default App;
